/* ── js/dbs/db.js ── */
// ══════════════════════════════════════════════════
// DB.JS — Carregamento inicial (loadAllFromSupabase)
// Funções de salvar/deletar ficam nos arquivos db-*.js
// ══════════════════════════════════════════════════

async function loadAllFromSupabase() {
  if (!currentUser) return;
  setSyncing(true);
  try {
    const uid = currentUser.id;

    // ── Fase 1: perfil + contextos (necessário antes dos dados) ──
    const [ctxIdRes, ctxRes, prRes] = await Promise.all([
      sb.rpc('ensure_personal_context', { p_user_id: uid }),
      sb.from('contexts').select('*').eq('user_id', uid).order('created_at'),
      sb.from('user_profiles').select('*').eq('user_id', uid).maybeSingle(),
    ]);

    const contexts = (ctxRes.data || []).map(r => ({
      id: r.id, name: r.name, type: r.type, parentId: r.parent_id, color: r.color
    }));
    S.contexts = contexts;
    S.profile = {
      nickname: prRes?.data?.nickname || '',
      disabled: prRes?.data?.disabled || false,
      pjEnabled: prRes?.data?.pj_enabled || false
    };

    // Determina contexto ativo: respeita preferência salva ou usa pessoal
    if (!S.activeContext) {
      const savedCtxId = localStorage.getItem('fin_active_ctx');
      const savedCtx   = savedCtxId ? contexts.find(c => c.id === savedCtxId) : null;
      const personalId = ctxIdRes.data;
      const personalCtx = savedCtx ||
        contexts.find(c => c.type === 'personal') ||
        (personalId ? contexts.find(c => c.id === personalId) : null) ||
        contexts[0] || null;
      S.activeContext = personalCtx;
    }

    if (!S.activeContext) {
      console.warn('[loadAll] Nenhum contexto disponível');
      setSyncing(false);
      return;
    }

    const cid = S.activeContext.id;

    // ── Fase 2: dados filtrados pelo contexto ativo ──
    const [mRes, bRes, tRes, pRes, rRes, iRes, sRes, instRes, gbRes, rmRes, dvRes, clRes, anRes, asRes] = await Promise.all([
      sb.from('months').select('*').eq('user_id', uid).eq('context_id', cid).order('created_at'),
      sb.from('banks').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('transacoes').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('pix_entries').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('recurrents').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('incomes').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('subscriptions').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('installments').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('banks_global').select('*').eq('user_id', uid).eq('context_id', cid).order('created_at'),
      sb.from('receivable_marks').select('*').eq('user_id', uid).eq('context_id', cid),
      sb.from('dev_users').select('*').order('added_at'),
      sb.from('changelog_entries').select('*').order('position', { ascending: false }).order('created_at', { ascending: false }),
      sb.from('announcements').select('*').order('created_at', { ascending: false }),
      sb.from('app_settings').select('*'),
    ]);

    // ── Months + Banks (por mês) + Entries ──
    const months = (mRes.data || []).map(m => ({
      key: m.key, label: m.label, year: m.year, goal: m.goal,
      banks: (bRes.data || [])
        .filter(b => b.month_key === m.key)
        .map(b => ({
          name: b.name, color: b.color,
          entries: (tRes.data || [])
            .filter(t => t.month_key === m.key && t.bank_name === b.name)
            .map(t => ({
              id: t.id, desc: t.description, amount: parseFloat(t.amount),
              date: t.entry_date, owner: t.owner, person: t.person,
              category: t.category, note: t.note, type: t.type || 'normal',
              installCurrent: t.install_current, installTotal: t.install_total,
              groupId: t.group_id, autoInj: t.auto_injected,
              splitRatio: t.split_ratio ? parseFloat(t.split_ratio) : null
            }))
        }))
    }));

    // ── Pix ──
    const pixEntries = {};
    (pRes.data || []).forEach(p => {
      if (!pixEntries[p.month_key]) pixEntries[p.month_key] = [];
      pixEntries[p.month_key].push({
        id: p.id, to: p.to_person, amount: parseFloat(p.amount),
        date: p.entry_date, bank: p.bank_name, obs: p.obs
      });
    });

    // ── Contas Fixas ──
    const recurrents = {};
    (rRes.data || []).forEach(r => {
      if (!recurrents[r.month_key]) recurrents[r.month_key] = [];
      recurrents[r.month_key].push({
        id: r.id, desc: r.description, amount: parseFloat(r.amount),
        day: r.due_day, obs: r.obs
      });
    });

    // ── Entradas (receitas) ──
    const incomes = {};
    (iRes.data || []).forEach(i => {
      if (!incomes[i.month_key]) incomes[i.month_key] = [];
      incomes[i.month_key].push({
        id: i.id, desc: i.description, amount: parseFloat(i.amount),
        date: i.entry_date, incType: i.income_type, from: i.from_source,
        owner: i.owner, person: i.person, clientId: i.client_id || null
      });
    });

    // ── Assinaturas ──
    const parsePeople = v => {
      if (!v) return null;
      if (Array.isArray(v)) return v;
      try { return JSON.parse(v); } catch { return v.split(',').map(x => x.trim()); }
    };
    const parseValues = v => {
      if (!v) return null;
      if (Array.isArray(v)) return v.map(Number);
      try { return JSON.parse(v).map(Number); } catch { return null; }
    };
    const subscriptions = (sRes.data || []).map(s => ({
      id: s.id, name: s.name, amount: parseFloat(s.amount), cycle: s.cycle,
      bank: s.bank_name, day: s.due_day, startDate: s.start_date, endDate: s.end_date,
      owner: s.owner || 'mine',
      splitPeople: parsePeople(s.split_people),
      splitValues: parseValues(s.split_values),
      priceHistory: s.price_history
        ? (typeof s.price_history === 'string' ? JSON.parse(s.price_history) : s.price_history)
        : null
    }));

    // ── Parcelas futuras ──
    const installments = (instRes.data || []).map(i => ({
      id: i.id, gId: i.group_id, desc: i.description, amount: parseFloat(i.amount),
      total: i.total_parts, partNum: i.part_num, bankName: i.bank_name,
      owner: i.owner, person: i.person, cat: i.category,
      offset: i.month_offset, startKey: i.start_month_key, date: i.entry_date, done: i.done
    }));

    // ── Bancos Globais ──
    const globalBanks = (gbRes?.data || []).map(g => ({
      id: g.id, name: g.name, color: g.color
    }));

    // ── Marks de recebimento ──
    const receivableMarks = (rmRes?.data || []).map(r => ({
      id: r.id, monthKey: r.month_key, itemRef: r.item_ref, itemType: r.item_type,
      person: r.person, amount: parseFloat(r.amount), desc: r.description,
      bankName: r.bank_name, received: r.received, receivedAt: r.received_at
    }));

    // ── Popula estado global ──
    // ── Dev Users ──
    const devUsers = (dvRes?.data || []).map(r => ({ id: r.id, email: r.email, addedAt: r.added_at }));

    // ── Changelog Entries ──
    const changelogEntries = (clRes?.data || []).map(r => ({
      id: r.id, version: r.version, date: r.entry_date,
      title: r.title, summary: r.summary, items: r.items, position: r.position
    }));

    // profile já foi carregado na Fase 1; apenas atualiza anúncios
    S.announcements  = (anRes?.data || []).map(r => ({ id: r.id, message: r.message, active: r.active, createdAt: r.created_at }));

    // ── App Settings ──
    const settingsMap = {};
    (asRes?.data || []).forEach(r => { settingsMap[r.key] = r.value; });
    S.appSettings = {
      pjAvailable:  settingsMap['pj_available']  === 'true',
      updateNotify: settingsMap['update_notify'] === 'true',
    };
    S.months       = months;
    sortMonths();
    S.pixEntries   = pixEntries;
    S.recurrents   = recurrents;
    S.incomes      = incomes;
    S.subscriptions = subscriptions;
    S.installments = installments;
    S.globalBanks  = globalBanks;
    S.receivableMarks = receivableMarks;
    S.devUsers     = devUsers;
    S.changelogEntries = changelogEntries;

    // ── PJ: carrega clientes e impostos se contexto for PJ ──
    if (S.activeContext?.type !== 'personal') {
      S.pjClients = await dbLoadClients();
      S.pjTaxes   = await dbLoadTaxes();
    } else {
      S.pjClients = [];
      S.pjTaxes   = [];
    }

    // ── Mostra/oculta nav PJ + aplica identidade visual do contexto ──
    const pjNav = document.getElementById('pjNav');
    if (pjNav) pjNav.style.display = S.activeContext?.type !== 'personal' ? '' : 'none';
    applyContext(S.activeContext);

    // ── Seeding: migra bancos existentes para banks_global na primeira vez ──
    if (S.globalBanks.length === 0 && months.length > 0 && !gbRes?.error) {
      const seen = new Set();
      for (const m of months) {
        for (const b of m.banks) {
          if (!seen.has(b.name)) {
            seen.add(b.name);
            const gb = {
              id: 'gb_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6),
              name: b.name, color: b.color || 'azure'
            };
            S.globalBanks.push(gb);
            await dbSaveGlobalBank(gb);
          }
        }
      }
    }

    const saved = localStorage.getItem('fin_theme');
    if (saved) S.theme = saved;

  } catch (e) {
    console.error('Erro ao carregar dados:', e);
  }
  setSyncing(false);
}

// Troca o contexto ativo e recarrega todos os dados
async function switchContext(ctxId) {
  const ctx = S.contexts.find(c => c.id === ctxId);
  if (!ctx || S.activeContext?.id === ctxId) return;
  S.activeContext = ctx;
  localStorage.setItem('fin_active_ctx', ctxId);
  applyContext(ctx);
  // Limpa dados do contexto anterior
  S.months = []; S.currentMonth = null; S.currentBank = null;
  S.pixEntries = {}; S.recurrents = {}; S.incomes = {};
  S.subscriptions = []; S.installments = []; S.globalBanks = [];
  S.receivableMarks = []; S.pjClients = []; S.pjTaxes = [];
  renderContextSwitcher();
  await loadAllFromSupabase();
  renderMonthList();
  renderSubs();
  _renderDashImpl();
}

/* ── js/auth.js ── */
// ══════════════════════════════════════════════════
// AUTH.JS — Login, Cadastro, Logout, Sessão
// ══════════════════════════════════════════════════

// ── Mapa de erros Supabase → português ─────────────
const AUTH_ERRORS = {
  'Invalid login credentials':                      'E-mail ou senha incorretos.',
  'User already registered':                        'Este e-mail já está cadastrado. Use a aba Entrar.',
  'Email not confirmed':                            'Confirme seu e-mail antes de entrar. Verifique sua caixa de entrada (e o spam).',
  'Password should be at least 6 characters':       'A senha precisa ter pelo menos 6 caracteres.',
  'Unable to validate email address: invalid format': 'Formato de e-mail inválido.',
  'signup_disabled':                                'Cadastro desativado temporariamente.',
  'over_email_send_rate_limit':                     'Muitas tentativas. Aguarde alguns minutos e tente novamente.',
  'Email rate limit exceeded':                      'Limite de tentativas atingido. Aguarde alguns minutos.',
  'For security purposes, you can only request this once every 60 seconds': 'Aguarde 1 minuto antes de solicitar outro link.',
};

function _authErrMsg(err) {
  if (!err) return 'Erro desconhecido. Tente novamente.';
  // Verifica mensagem exata
  if (AUTH_ERRORS[err.message]) return AUTH_ERRORS[err.message];
  // Verifica por substring
  const msg = (err.message || '').toLowerCase();
  if (msg.includes('network') || msg.includes('fetch'))
    return 'Sem conexão. Verifique sua internet e tente novamente.';
  if (msg.includes('invalid email') || msg.includes('invalid format'))
    return 'Formato de e-mail inválido.';
  if (msg.includes('rate limit') || msg.includes('too many'))
    return 'Muitas tentativas. Aguarde alguns minutos.';
  if (msg.includes('weak password') || msg.includes('6 characters'))
    return 'A senha precisa ter pelo menos 6 caracteres.';
  // Fallback: mostra o erro original
  return err.message || 'Erro inesperado. Tente novamente.';
}

// ── Painéis da tela de auth ─────────────────────────
function showAuthPanel(panel) {
  document.getElementById('authPanelMain').style.display     = panel === 'main'     ? '' : 'none';
  document.getElementById('authPanelForgot').style.display   = panel === 'forgot'   ? '' : 'none';
  document.getElementById('authPanelRecovery').style.display = panel === 'recovery' ? '' : 'none';
  // Limpa mensagens ao trocar painel
  _clearAuthMsgs();
}

function _clearAuthMsgs() {
  ['authMsg','forgotMsg','recoveryMsg'].forEach(id => {
    const el = document.getElementById(id);
    if (el) { el.textContent = ''; el.className = 'auth-msg'; }
  });
}

function showMsg(id, msg, type) {
  const el = document.getElementById(id);
  if (!el) return;
  el.textContent = msg;
  el.className = 'auth-msg ' + (type || '');
}

// ── Tabs login / cadastro ───────────────────────────
function switchAuthTab(tab) {
  document.getElementById('tabLogin').classList.toggle('active', tab === 'login');
  document.getElementById('tabRegister').classList.toggle('active', tab === 'register');
  document.getElementById('authBtn').textContent = tab === 'login' ? 'Entrar' : 'Cadastrar';
  document.getElementById('authBtn').dataset.mode = tab;
  document.getElementById('fgConfirm').style.display = tab === 'register' ? '' : 'none';
  document.getElementById('authPassword').setAttribute('autocomplete', tab === 'login' ? 'current-password' : 'new-password');
  document.getElementById('btnForgot').style.display = tab === 'login' ? '' : 'none';
  showMsg('authMsg', '', '');
}

// ── Mostrar / ocultar senha ─────────────────────────
function toggleAuthEye(inputId, btn) {
  const inp = document.getElementById(inputId);
  if (!inp) return;
  const isHidden = inp.type === 'password';
  inp.type = isHidden ? 'text' : 'password';
  btn.style.opacity = isHidden ? '1' : '0.4';
}

// ── Login / Cadastro ────────────────────────────────
async function handleAuth() {
  const email    = (document.getElementById('authEmail').value || '').trim();
  const password = document.getElementById('authPassword').value;
  const confirm  = document.getElementById('authConfirm').value;
  const mode     = document.getElementById('authBtn').dataset.mode || 'login';
  const btn      = document.getElementById('authBtn');

  // Validações locais
  if (!email)                       { showMsg('authMsg', 'Informe seu e-mail.', 'err'); return; }
  if (!email.includes('@') || !email.includes('.'))
                                    { showMsg('authMsg', 'Formato de e-mail inválido.', 'err'); return; }
  if (!password)                    { showMsg('authMsg', 'Informe sua senha.', 'err'); return; }
  if (password.length < 6)         { showMsg('authMsg', 'A senha precisa ter pelo menos 6 caracteres.', 'err'); return; }
  if (mode === 'register' && password !== confirm)
                                    { showMsg('authMsg', 'As senhas não coincidem.', 'err'); return; }

  btn.textContent = 'Aguarde...';
  btn.disabled = true;

  try {
    if (mode === 'register') {
      const result = await sb.auth.signUp({ email, password });
      if (result.error) throw result.error;

      // Supabase retorna user mas sem session quando email já existe (identities vazio)
      if (result.data.user?.identities?.length === 0) {
        throw { message: 'User already registered' };
      }

      if (result.data.session) {
        // Confirmação de e-mail desativada → loga direto
        currentUser = result.data.user;
        onLoginSuccess();
        return;
      } else {
        // Confirmação de e-mail ativa
        showMsg('authMsg', '✓ Conta criada! Verifique seu e-mail para confirmar o cadastro (cheque o spam também).', 'ok');
        btn.textContent = 'Cadastrar';
        btn.disabled = false;
        return;
      }
    } else {
      const result = await sb.auth.signInWithPassword({ email, password });
      if (result.error) throw result.error;
      currentUser = result.data.user;
      onLoginSuccess();
    }
  } catch (err) {
    showMsg('authMsg', _authErrMsg(err), 'err');
    btn.textContent = mode === 'login' ? 'Entrar' : 'Cadastrar';
    btn.disabled = false;
  }
}

// Mantém compatibilidade com onkeydown inline existente
function showAuthMsg(msg, type) {
  showMsg('authMsg', msg, type === 'err' ? 'err' : type === 'ok' ? 'ok' : '');
}

// ── Esqueci a senha ─────────────────────────────────
async function handleForgotPwd() {
  const email = (document.getElementById('forgotEmail').value || '').trim();
  const btn   = document.getElementById('forgotBtn');

  if (!email || !email.includes('@')) {
    showMsg('forgotMsg', 'Informe um e-mail válido.', 'err');
    return;
  }

  btn.textContent = 'Enviando...';
  btn.disabled = true;

  const { error } = await sb.auth.resetPasswordForEmail(email, {
    redirectTo: window.location.origin + window.location.pathname
  });

  if (error) {
    showMsg('forgotMsg', _authErrMsg(error), 'err');
    btn.textContent = 'Enviar link';
    btn.disabled = false;
    return;
  }

  showMsg('forgotMsg', '✓ Link enviado! Verifique seu e-mail (e a pasta de spam).', 'ok');
  btn.textContent = 'Enviado';
  // Não reabilita o botão para evitar reenvio acidental
}

// ── Redefinir senha (recovery) ──────────────────────
async function handleRecoveryPwd() {
  const pwd     = document.getElementById('recoveryPwd').value;
  const confirm = document.getElementById('recoveryConfirm').value;
  const btn     = document.getElementById('recoveryBtn');

  if (!pwd || pwd.length < 6)  { showMsg('recoveryMsg', 'A senha precisa ter pelo menos 6 caracteres.', 'err'); return; }
  if (pwd !== confirm)          { showMsg('recoveryMsg', 'As senhas não coincidem.', 'err'); return; }

  btn.textContent = 'Salvando...';
  btn.disabled = true;

  const { error } = await sb.auth.updateUser({ password: pwd });

  if (error) {
    showMsg('recoveryMsg', _authErrMsg(error), 'err');
    btn.textContent = 'Salvar nova senha';
    btn.disabled = false;
    return;
  }

  showMsg('recoveryMsg', '✓ Senha alterada com sucesso! Entrando...', 'ok');
  setTimeout(() => {
    document.getElementById('authScreen').style.display = 'none';
  }, 1500);
}

// ── Trocar senha (usuário logado) ───────────────────
function openChangePwdModal() {
  openModal('mChangePwd');
}

async function handleChangePwd() {
  const pwd     = (document.getElementById('changePwd').value || '');
  const confirm = (document.getElementById('changePwdConfirm').value || '');
  const btn     = document.getElementById('changePwdBtn');

  if (!pwd || pwd.length < 6)  { showToast('A senha precisa ter pelo menos 6 caracteres.', 'error'); return; }
  if (pwd !== confirm)          { showToast('As senhas não coincidem.', 'error'); return; }

  btn.textContent = 'Salvando...';
  btn.disabled = true;

  const { error } = await sb.auth.updateUser({ password: pwd });

  btn.textContent = 'Salvar';
  btn.disabled = false;

  if (error) { showToast(_authErrMsg(error), 'error'); return; }

  closeModal('mChangePwd');
  document.getElementById('changePwd').value = '';
  document.getElementById('changePwdConfirm').value = '';
  showToast('✓ Senha alterada com sucesso');
}

// ── Login bem-sucedido ──────────────────────────────
async function onLoginSuccess() {
  document.getElementById('authScreen').style.display = 'none';
  showAuthPanel('main'); // reseta para painel principal para próxima vez
  const emailEl = document.getElementById('userEmail');
  if (emailEl) emailEl.textContent = currentUser.email;
  _profileUpdateSidebarAvatar();

  showSplash();

  const dashEl = document.getElementById('dashContent');
  if (dashEl) dashEl.innerHTML = renderSkeleton();

  await loadAllFromSupabase();

  // ── Verifica se conta foi desativada ──
  if (S.profile?.disabled) {
    await sb.auth.signOut();
    currentUser = null;
    document.getElementById('authScreen').style.display = 'flex';
    const msg = document.getElementById('authMsg');
    if (msg) { msg.textContent = 'Sua conta foi desativada. Entre em contato com o suporte.'; msg.style.color = 'var(--red)'; }
    hideSplash();
    return;
  }

  // ── Dev Panel ──
  S.isDev = S.devUsers.some(d => d.email === currentUser.email);
  const devNav = document.getElementById('nav-dev');
  if (devNav) devNav.style.display = S.isDev ? 'flex' : 'none';
  if (S.isDev && S.changelogEntries.length === 0) {
    await dbSeedChangelog(CHANGELOG);
    S.changelogEntries = await dbLoadChangelogEntries();
  }

  renderContextSwitcher();
  renderMonthList();
  renderSubs();
  checkVersionBanner();
  renderAnnouncementBanner();
  // Mostra ponto vermelho no nav se versão nova
  const seen = localStorage.getItem('fin_seen_version');
  if (seen !== APP_VERSION) {
    const dot = document.getElementById('changelogDot');
    if (dot) dot.style.display = 'block';
    const banner = document.getElementById('bannerVersion');
    if (banner) banner.textContent = APP_VERSION;
  }

  if (S.currentMonth) {
    selectMonth(S.currentMonth, false);
  } else {
    _renderDashImpl();
  }

  applyTheme();
}

function logout() {
  openModal('mLogout');
}

async function confirmLogout() {
  closeModal('mLogout');
  await sb.auth.signOut();
  currentUser = null;
  localStorage.removeItem('fin_active_ctx');
  S = { ...defaultState() };
  const devNavEl = document.getElementById('nav-dev');
  if (devNavEl) devNavEl.style.display = 'none';
  showAuthPanel('main');
  document.getElementById('authScreen').style.display = 'flex';
  document.getElementById('authEmail').value = '';
  document.getElementById('authPassword').value = '';
  document.getElementById('authBtn').textContent = 'Entrar';
  document.getElementById('authBtn').disabled = false;
  document.getElementById('authBtn').dataset.mode = 'login';
  showMsg('authMsg', '', '');
}

// ── Verificar sessão existente ao carregar ──────────
sb.auth.getSession().then(({ data: { session } }) => {
  if (session) {
    currentUser = session.user;
    onLoginSuccess();
  } else {
    document.getElementById('authScreen').style.display = 'flex';
  }
});

sb.auth.onAuthStateChange((event, session) => {
  if (event === 'PASSWORD_RECOVERY') {
    // Usuário clicou no link de recuperação — mostra painel de nova senha
    document.getElementById('authScreen').style.display = 'flex';
    showAuthPanel('recovery');
  }
  if (event === 'SIGNED_OUT') {
    document.getElementById('authScreen').style.display = 'flex';
  }
});

/* ── js/months.js ── */
// ══════════════════════════════════════════════════
// MONTHS.JS — CRUD de Meses
// ══════════════════════════════════════════════════

const MONTH_ORDER = {Janeiro:1,Fevereiro:2,Março:3,Abril:4,Maio:5,Junho:6,
                     Julho:7,Agosto:8,Setembro:9,Outubro:10,Novembro:11,Dezembro:12};

function sortMonths() {
  S.months.sort((a, b) => {
    const ya = parseInt(a.year), yb = parseInt(b.year);
    if (ya !== yb) return ya - yb;
    return (MONTH_ORDER[a.label] || 0) - (MONTH_ORDER[b.label] || 0);
  });
}

async function addMonth() {
  const m = document.getElementById('mSel').value;
  const y = document.getElementById('mYear').value;
  const key = m + '/' + y;
  if (S.months.find(x => x.key === key)) { alert('Mês já existe.'); return; }
  const goal = parseFloat(document.getElementById('mMonthGoal').value) || null;
  const banks = S.globalBanks.map(gb => ({ name: gb.name, color: gb.color, entries: [] }));
  const month = { key, label: m, year: y, banks, goal };
  S.months.push(month);
  sortMonths();
  setSyncing(true);
  await dbSaveMonth(month);
  for (const b of banks) await dbSaveBank(key, b);
  await injectInstallments(key);
  setSyncing(false);
  renderMonthList();
  selectMonth(key);
  closeModal('mMonth');
  document.getElementById('mMonthGoal').value = '';
  showToast('✓ Mês criado');
}

async function copyLastMonth() {
  if (S.months.length === 0) { alert('Nenhum mês para copiar.'); return; }
  const last = S.months[S.months.length - 1];
  const m = document.getElementById('mSel').value;
  const y = document.getElementById('mYear').value;
  const key = m + '/' + y;
  if (S.months.find(x => x.key === key)) { alert('Mês já existe.'); return; }
  const goal = parseFloat(document.getElementById('mMonthGoal').value) || last.goal || null;
  const banks = S.globalBanks.length > 0
    ? S.globalBanks.map(gb => ({ name: gb.name, color: gb.color, entries: [] }))
    : last.banks.map(b => ({ ...b, entries: [] }));
  const month = { key, label: m, year: y, banks, goal };
  S.months.push(month);
  sortMonths();
  setSyncing(true);
  await dbSaveMonth(month);
  for (const b of banks) await dbSaveBank(key, b);
  if (S.recurrents[last.key]) {
    S.recurrents[key] = (S.recurrents[last.key] || []).map(r => ({ ...r, id: Date.now() + Math.random() }));
    for (const r of S.recurrents[key]) await dbSaveRecurrent(key, r);
  }
  await injectInstallments(key);
  setSyncing(false);
  renderMonthList();
  selectMonth(key);
  closeModal('mMonth');
  document.getElementById('mMonthGoal').value = '';
}

// ── NOVO: Deletar mês e todos os dados relacionados ──
async function deleteMonth(key) {
  if (!confirm('Excluir este mês e todos os lançamentos? Essa ação não pode ser desfeita.')) return;
  setSyncing(true);

  const m = S.months.find(x => x.key === key);
  if (m) {
    // Deleta todas as entradas de todos os bancos
    for (const b of m.banks) {
      for (const e of b.entries) await dbDeleteEntry(e.id);
    }
    // Deleta bancos
    await sb.from('banks')
      .delete()
      .eq('user_id', currentUser.id)
      .eq('month_key', key);
  }

  // Deleta pix, recorrentes, entradas do mês
  await sb.from('pix_entries').delete().eq('user_id', currentUser.id).eq('month_key', key);
  await sb.from('recurrents').delete().eq('user_id', currentUser.id).eq('month_key', key);
  await sb.from('incomes').delete().eq('user_id', currentUser.id).eq('month_key', key);
  await sb.from('transacoes').delete().eq('user_id', currentUser.id).eq('month_key', key);
  await sb.from('months').delete().eq('user_id', currentUser.id).eq('key', key);

  // Atualiza estado local
  S.months = S.months.filter(x => x.key !== key);
  delete S.pixEntries[key];
  delete S.recurrents[key];
  delete S.incomes[key];

  if (S.currentMonth === key) {
    S.currentMonth = S.months.length ? S.months[S.months.length - 1].key : null;
  }

  setSyncing(false);
  renderMonthList();

  if (S.currentMonth) {
    selectMonth(S.currentMonth);
  } else {
    document.getElementById('dashContent').innerHTML = '<div class="empty">selecione ou crie um mês<br>para começar</div>';
    document.getElementById('tbTitle').textContent = 'Selecione um mês';
    document.getElementById('tbSub').textContent = 'nenhum mês selecionado';
    document.getElementById('tbActions').innerHTML = '';
  }
}

function monthTotal(m) {
  let t = m.banks.reduce((s, b) => s + b.entries.reduce((ss, e) => ss + e.amount, 0), 0);
  t += (S.recurrents[m.key] || []).reduce((s, r) => s + r.amount, 0);
  t += (S.pixEntries[m.key] || []).reduce((s, p) => s + p.amount, 0);
  return t;
}

function selectMonth(key, render = true) {
  // ── Fecha sidebar no mobile ao selecionar mês ──
  const sb = document.getElementById('sb');
  if (sb && sb.classList.contains('open')) toggleSidebar();

  S.currentMonth = key;
  const m = getMonth();
  if (!m) return;
  const tbTitle = document.getElementById('tbTitle');
  const tbSub = document.getElementById('tbSub');
  if (tbTitle) tbTitle.textContent = m.label + ' ' + m.year;
  if (tbSub) tbSub.textContent = m.banks.length + ' banco(s)' + (m.goal ? ` · meta R$${fmt(m.goal)}` : '');
  S.currentBank = m.banks.length ? m.banks[0].name : null;
  buildActions();
  renderMonthList();
  if (render) renderDash();
  save();
}

function getMonth() {
  return S.months.find(m => m.key === S.currentMonth);
}

function buildActions() {
  const el = document.getElementById('tbActions');
  if (!el) return;
  if (getMonth()) {
    el.innerHTML = `
      <button class="btn btn-ghost btn-sm act-trigger" onclick="toggleActMenu(event)" title="Ações do mês">
        <svg width="16" height="16" fill="currentColor" viewBox="0 0 24 24"><circle cx="12" cy="5" r="2"/><circle cx="12" cy="12" r="2"/><circle cx="12" cy="19" r="2"/></svg>
      </button>
      <div class="act-list" id="actMenuList">
        <button class="btn btn-ghost btn-sm" onclick="openModal('mGoal');closeActMenu()">🎯 Meta</button>
        <button class="btn btn-ghost btn-sm" onclick="openAI();closeActMenu()">📄 Extrato IA</button>
        <button class="btn btn-ghost btn-sm" onclick="exportMonthPDF();closeActMenu()">📥 PDF</button>
      </div>`;
  } else {
    el.innerHTML = '';
  }
}

// ══════════════════════════════════════════════════
// EDIT MONTH — Editar label, ano e meta do mês
// ══════════════════════════════════════════════════

function openEditMonth(key) {
  const m = S.months.find(x => x.key === key);
  if (!m) return;

  const months = ['Janeiro','Fevereiro','Março','Abril','Maio','Junho',
                  'Julho','Agosto','Setembro','Outubro','Novembro','Dezembro'];

  document.getElementById('editMSel').value = m.label;
  document.getElementById('editMYear').value = m.year;
  document.getElementById('editMGoal').value = m.goal || '';
  document.getElementById('editMKey').value = key;

  openModal('mEditMonth');
}

async function saveEditMonth() {
  const oldKey  = document.getElementById('editMKey').value;
  const label   = document.getElementById('editMSel').value;
  const year    = document.getElementById('editMYear').value;
  const goal    = parseFloat(document.getElementById('editMGoal').value) || null;
  const newKey  = label + '/' + year;

  const m = S.months.find(x => x.key === oldKey);
  if (!m) return;

  // ── Sem mudança de key: só atualiza meta ──
  if (newKey === oldKey) {
    m.goal = goal;
    setSyncing(true);
    await dbSaveMonth(m);
    setSyncing(false);
    renderMonthList();
    if (S.currentMonth === oldKey) selectMonth(oldKey, true);
    closeModal('mEditMonth');
    return;
  }

  // ── Chave nova já existe? ──
  if (S.months.find(x => x.key === newKey)) {
    alert('Já existe um mês com esse nome/ano.');
    return;
  }

  setSyncing(true);

  // 1. Atualiza objeto local
  m.key   = newKey;
  m.label = label;
  m.year  = year;
  m.goal  = goal;

  // 2. Salva novo mês no Supabase
  await dbSaveMonth(m);

  // 3. Migra bancos e entradas
  for (const b of m.banks) {
    await dbSaveBank(newKey, b);
    for (const e of b.entries) {
      await dbSaveEntry(newKey, b.name, e);
      await dbDeleteEntry(e.id); // remove da key antiga (upsert por id já sobrescreve, mas garante month_key)
    }
    // Remove banco da key antiga
    await sb.from('banks')
      .delete()
      .eq('user_id', currentUser.id)
      .eq('month_key', oldKey)
      .eq('name', b.name);
  }

  // 4. Migra pix
  const pixList = S.pixEntries[oldKey] || [];
  S.pixEntries[newKey] = pixList;
  delete S.pixEntries[oldKey];
  for (const px of pixList) await dbSavePix(newKey, px);
  await sb.from('pix_entries').delete()
    .eq('user_id', currentUser.id).eq('month_key', oldKey);

  // 5. Migra recorrentes
  const recList = S.recurrents[oldKey] || [];
  S.recurrents[newKey] = recList;
  delete S.recurrents[oldKey];
  for (const r of recList) await dbSaveRecurrent(newKey, r);
  await sb.from('recurrents').delete()
    .eq('user_id', currentUser.id).eq('month_key', oldKey);

  // 6. Migra incomes
  const incList = S.incomes[oldKey] || [];
  S.incomes[newKey] = incList;
  delete S.incomes[oldKey];
  for (const i of incList) await dbSaveIncome(newKey, i);
  await sb.from('incomes').delete()
    .eq('user_id', currentUser.id).eq('month_key', oldKey);

  // 7. Deleta mês antigo do Supabase
  await sb.from('months').delete()
    .eq('user_id', currentUser.id).eq('key', oldKey);

  // 8. Atualiza currentMonth se necessário
  if (S.currentMonth === oldKey) S.currentMonth = newKey;

  setSyncing(false);
  renderMonthList();
  selectMonth(S.currentMonth, true);
  closeModal('mEditMonth');
}

// ══════════════════════════════════════════════════
// DELETE MONTH MODAL — Confirmação com dados do mês
// ══════════════════════════════════════════════════

function openDeleteMonth(key) {
  const m = S.months.find(x => x.key === key);
  if (!m) return;

  const total = monthTotal(m);

  document.getElementById('deleteMonthLabel').textContent = m.label + ' ' + m.year;
  document.getElementById('deleteMonthTotal').textContent =
    'Total lançado: R$ ' + fmt(total) +
    ' · ' + m.banks.flatMap(b => b.entries).length + ' lançamento(s)';
  document.getElementById('deleteMonthKey').value = key;

  openModal('mDeleteMonth');
}

async function executeDeleteMonth() {
  const key = document.getElementById('deleteMonthKey').value;
  if (!key) return;
  closeModal('mDeleteMonth');
  await deleteMonth(key); // reutiliza a lógica existente em deleteMonth()
}

/* ── js/banks.js ── */
// ══════════════════════════════════════════════════
// BANKS.JS — CRUD de Bancos
// ══════════════════════════════════════════════════

function pickColor(el) {
  el.closest('.color-grid').querySelectorAll('.color-dot').forEach(c => c.classList.remove('sel'));
  el.classList.add('sel');
  S.pickedColor = el.dataset.c;
}

function buildColorGrid(targetId = 'colorGrid') {
  const g = document.getElementById(targetId);
  if (!g) return;
  g.innerHTML = Object.entries(PALETTE).map(([k, v]) => `
    <div class="color-dot ${S.pickedColor === k ? 'sel' : ''}"
      style="background:${v}"
      data-c="${k}"
      onclick="pickColor(this)"
      title="${k}">
    </div>`).join('');
}

async function addBank() {
  const name = normalizeName(document.getElementById('bName').value);
  if (!name) return;
  const m = getMonth();
  if (m.banks.find(b => b.name.toLowerCase() === name.toLowerCase())) { alert('Já existe.'); return; }
  const bank = { name, color: S.pickedColor, entries: [] };
  m.banks.push(bank);
  setSyncing(true);
  await dbSaveBank(m.key, bank);
  setSyncing(false);
  S.currentBank = name;
  renderDash();
  buildActions();
  closeModal('mBank');
  document.getElementById('bName').value = '';
  showToast('✓ Banco criado');
}

function selectBank(n) {
  S.currentBank = n;
  save();
  renderDash();
}

// ══════════════════════════════════════════════════
// BANCOS GLOBAIS
// ══════════════════════════════════════════════════

function openGlobalBankM() {
  S.pickedColor = 'azure';
  buildColorGrid('gbColorGrid');
  document.getElementById('gbName').value = '';
  openModal('mGlobalBank');
}

async function addGlobalBank() {
  const name = normalizeName(document.getElementById('gbName').value);
  if (!name) return;
  if (S.globalBanks.find(b => b.name.toLowerCase() === name.toLowerCase())) { showToast('Banco já existe', 'error'); return; }
  const gb = {
    id: 'gb_' + Date.now() + '_' + Math.random().toString(36).slice(2, 6),
    name, color: S.pickedColor || 'azure'
  };
  S.globalBanks.push(gb);
  setSyncing(true);
  await dbSaveGlobalBank(gb);
  setSyncing(false);
  closeModal('mGlobalBank');
  showToast('✓ Banco adicionado');
  renderBanksView();
}

async function deleteGlobalBank(id) {
  if (!confirm('Remover da lista global? Os lançamentos existentes não serão apagados.')) return;
  S.globalBanks = S.globalBanks.filter(b => b.id !== id);
  if (S._selectedBankId === id) S._selectedBankId = null;
  setSyncing(true);
  await dbDeleteGlobalBank(id);
  setSyncing(false);
  showToast('Banco removido');
  renderBanksView();
}

function selectBankStat(id) {
  S._selectedBankId = S._selectedBankId === id ? null : id;
  if (S._selectedBankId) {
    S._bankStatsYear = S._bankStatsYear || String(new Date().getFullYear());
  }
  renderBanksView();
}

function renderBanksView() {
  const el = document.getElementById('banksContent');
  if (!el) return;

  if (S.globalBanks.length === 0) {
    el.innerHTML = `
      <div class="empty" style="padding:48px 0">
        <svg width="40" height="40" fill="none" stroke="currentColor" stroke-width="1.5" viewBox="0 0 24 24" style="margin-bottom:12px;color:var(--text3)">
          <rect x="2" y="7" width="20" height="14" rx="2"/><path d="M16 7V5a2 2 0 0 0-2-2h-4a2 2 0 0 0-2 2v2"/>
        </svg>
        <div style="font-size:15px;font-weight:600;margin-bottom:6px">Nenhum banco cadastrado</div>
        <div style="font-size:13px;color:var(--text3);margin-bottom:16px">Adicione seus bancos e cartões</div>
        <button class="btn btn-primary btn-sm" onclick="openGlobalBankM()">+ Adicionar banco</button>
      </div>`;
    return;
  }

  const infoText = `<div style="background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:10px 14px;font-size:12px;color:var(--text2);margin-bottom:16px;line-height:1.5">
    ℹ️ Bancos cadastrados aqui aparecem automaticamente em <strong>novos meses</strong>. Para adicionar um banco em um mês já criado, selecione o mês e use <strong>+ Banco</strong> na aba Gastos.
  </div>`;

  const selId = S._selectedBankId;
  const cards = S.globalBanks.map(gb => {
    const col = PALETTE[gb.color] || gb.color || '#4d9fff';
    const active = gb.id === selId;
    return `<div class="bank-global-card ${active ? 'bgc-active' : ''}" onclick="selectBankStat('${gb.id}')">
      <div class="bgc-dot" style="background:${col}"></div>
      <div class="bgc-name">${gb.name}</div>
      <button class="btn btn-ghost btn-sm bgc-del" onclick="event.stopPropagation();deleteGlobalBank('${gb.id}')">✕</button>
    </div>`;
  }).join('');

  const stats = selId ? buildBankStats(selId) : '';

  el.innerHTML = `
    ${infoText}
    <div class="bgc-list">
      ${cards}
      <div class="bank-global-card bgc-add" onclick="openGlobalBankM()">
        <span style="font-size:20px;color:var(--text3);line-height:1">+</span>
        <span style="color:var(--text3);font-size:12px">Novo banco</span>
      </div>
    </div>
    ${stats}`;
}

function buildBankStats(bankId) {
  const gb = S.globalBanks.find(b => b.id === bankId);
  if (!gb) return '';

  const year = S._bankStatsYear || String(new Date().getFullYear());
  const col = PALETTE[gb.color] || gb.color || '#4d9fff';
  const yearMonths = S.months.filter(m => String(m.year) === String(year));

  let totalYear = 0, myGastos = 0, othGastos = 0;
  const monthData = [];

  for (const m of yearMonths) {
    const bk = m.banks.find(b => b.name === gb.name);
    let mTotal = 0, mMine = 0, mOther = 0;
    if (bk) {
      for (const e of bk.entries) {
        if (e.owner === 'other') {
          mOther += e.amount; othGastos += e.amount;
        } else if (e.owner === 'split') {
          const cnt = (e.splitPeople?.length || 1) + 1;
          const mine = e.amount / cnt;
          mMine += mine; mOther += e.amount - mine;
          myGastos += mine; othGastos += e.amount - mine;
        } else {
          mMine += e.amount; myGastos += e.amount;
        }
        mTotal += e.amount; totalYear += e.amount;
      }
    }
    monthData.push({ label: m.label, total: mTotal, mine: mMine, other: mOther });
  }

  // Entradas (incomes) do ano — não filtradas por banco (income não tem campo bank)
  let myInc = 0, othInc = 0;
  for (const m of yearMonths) {
    for (const i of (S.incomes[m.key] || [])) {
      if (i.owner === 'other') othInc += i.amount;
      else myInc += i.amount;
    }
  }

  // Seletor de ano
  const years = [...new Set(S.months.map(m => String(m.year)))].sort().reverse();
  const yearSel = years.length > 1 ? `
    <select class="modal-input" style="width:auto;padding:4px 8px;font-size:12px"
      onchange="S._bankStatsYear=this.value;renderBanksView()">
      ${years.map(y => `<option value="${y}"${y === year ? ' selected' : ''}>${y}</option>`).join('')}
    </select>` : `<span style="font-family:var(--mono);font-size:12px;color:var(--text2)">${year}</span>`;

  // Barras mês a mês
  const maxAmt = Math.max(...monthData.map(m => m.total), 1);
  const bars = monthData.length ? monthData.map(md => {
    const pct = Math.round((md.total / maxAmt) * 100);
    return `<div class="bbc-row">
      <span class="bbc-label">${md.label.slice(0, 3)}</span>
      <div class="bbc-bar-wrap"><div class="bbc-bar" style="width:${pct}%;background:${col}"></div></div>
      <span class="bbc-val">${md.total > 0 ? 'R$ ' + fmt(md.total) : '—'}</span>
    </div>`;
  }).join('') : `<div style="color:var(--text3);font-size:13px;padding:8px 0">Nenhum dado para este ano</div>`;

  return `
    <div class="tbl-block" style="margin-top:20px">
      <div class="tbl-head">
        <span class="tbl-title" style="color:${col};font-size:13px">${gb.name}</span>
        ${yearSel}
      </div>
      <div style="padding:16px 18px">
        <div class="summary-grid" style="margin-bottom:20px">
          <div class="card"><div class="card-lbl">Total ${year}</div><div class="card-val">R$ ${fmt(totalYear)}</div></div>
          <div class="card"><div class="card-lbl">Meus gastos</div><div class="card-val a">R$ ${fmt(myGastos)}</div></div>
          <div class="card"><div class="card-lbl">Gastos terceiros</div><div class="card-val o">R$ ${fmt(othGastos)}</div></div>
          <div class="card"><div class="card-lbl">Entradas minhas¹</div><div class="card-val" style="color:var(--green)">R$ ${fmt(myInc)}</div></div>
          <div class="card"><div class="card-lbl">Entradas terceiros¹</div><div class="card-val" style="color:var(--green)">R$ ${fmt(othInc)}</div></div>
        </div>
        <div class="card-lbl" style="margin-bottom:10px;text-transform:uppercase;letter-spacing:1px">Mês a mês — ${year}</div>
        <div class="bank-bar-chart">${bars}</div>
        ${myInc + othInc > 0 ? `<div style="font-size:10px;color:var(--text3);margin-top:12px;font-family:var(--mono)">¹ Total de entradas do ano (todos os bancos)</div>` : ''}
      </div>
    </div>`;
}

async function deleteBank(name) {
  if (!confirm(`Excluir o banco "${name}" e todos os seus lançamentos?`)) return;

  const m = getMonth();
  if (!m) return;

  const bank = m.banks.find(b => b.name === name);
  if (!bank) return;

  setSyncing(true);

  // Deleta todas as entradas do banco no Supabase
  for (const e of bank.entries) {
    await dbDeleteEntry(e.id);
  }

  // Deleta o banco no Supabase
  await sb.from('banks')
    .delete()
    .eq('user_id', currentUser.id)
    .eq('month_key', m.key)
    .eq('name', name);

  // Atualiza estado local
  m.banks = m.banks.filter(b => b.name !== name);

  // Reseta currentBank se era o banco deletado
  if (S.currentBank === name) {
    S.currentBank = m.banks.length ? m.banks[0].name : null;
  }

  setSyncing(false);
  renderDash();
  buildActions();
  showToast('Banco excluído');
}

/* ── js/entries.js ── */
// ══════════════════════════════════════════════════
// ENTRIES.JS — CRUD de Lançamentos + Detail Modal
// ══════════════════════════════════════════════════

function openEntryM(editId = null, editBank = null) {
  const m = getMonth();
  if (!m || !m.banks.length) { alert('Adicione um banco primeiro.'); return; }
  fillSel('eBank', m.banks.map(b => b.name));
  if (S.currentBank) document.getElementById('eBank').value = S.currentBank;
  document.getElementById('editEntryId').value = '';
  document.getElementById('editBankName').value = '';
  const titleEl = document.getElementById('entryTitle');
  if (titleEl) titleEl.firstChild.textContent = editId ? 'Editar Lançamento ' : 'Novo Lançamento ';
  clr('eDesc', 'eAmt', 'ePerson', 'eCat', 'eNote');
  // Restringe data ao mês da pasta
  const _m = getMonth();
  if (_m) {
    const { min, max } = getMonthDateRange(_m);
    const dateEl = document.getElementById('eDate');
    dateEl.setAttribute('min', min);
    dateEl.setAttribute('max', max);
    const t = today();
    dateEl.value = (t >= min && t <= max) ? t : min;
  }
  document.getElementById('eInstTotal').value = '';
  document.getElementById('eInstCur').value = '1';
  S.splitPeople = [];
  S.splitCount = 2;
  S.splitCustomPct = false;
  S.splitMyPct = null;
  setEType('normal');
  setOwner('mine');
  renderCatChips();
  renderPersonChips();
  updateInstallHint(); // ← hint inicial

  if (editId && editBank) {
    const bk = getMonth().banks.find(b => b.name === editBank);
    const en = bk?.entries.find(e => String(e.id) === String(editId));
    if (en) {
      document.getElementById('editEntryId').value = editId;
      document.getElementById('editBankName').value = editBank;
      document.getElementById('eDesc').value = en.desc;
      // Se for parcelado, mostra o valor total (parcela × total)
      document.getElementById('eAmt').value = en.type === 'installment'
        ? (en.amount * en.installTotal).toFixed(2)
        : en.amount;
      document.getElementById('eDate').value = en.date || today();
      document.getElementById('eBank').value = editBank;
      renderCatChips(en.category || '');
      document.getElementById('eCat').value = en.category || '';
      document.getElementById('eNote').value = en.note || '';
      if (en.owner === 'split') {
        S.splitPeople = en.splitPeople || (en.person ? en.person.split(', ').filter(Boolean) : []);
        S.splitCount = S.splitPeople.length + 1 || 2;
        const expectedRatio = 1 / S.splitCount;
        const storedRatio = en.splitRatio ?? expectedRatio;
        S.splitCustomPct = Math.abs(storedRatio - expectedRatio) > 0.001;
        S.splitMyPct = S.splitCustomPct ? Math.round(storedRatio * 100) : null;
      } else {
        S.splitPeople = [];
        S.splitCount = 2;
        S.splitCustomPct = false;
        S.splitMyPct = null;
      }
      setEType(en.type || 'normal');
      setOwner(en.owner || 'mine');
      if (en.owner !== 'split' && en.person) {
        document.getElementById('ePerson').value = en.person;
      }
      if (en.installTotal) {
        document.getElementById('eInstTotal').value = en.installTotal;
        document.getElementById('eInstCur').value = en.installCurrent;
        updateInstallHint();
      }
    }
  }
  openModal('mEntry');
}

function setEType(t) {
  S.entryType = t;
  ['tNormal', 'tInstall', 'tPix', 'tDebit', 'tBoleto'].forEach(id => {
    const el = document.getElementById(id);
    if (el) el.classList.remove('active');
  });
  // cash → boleto (compatibilidade com entradas antigas)
  const map = { normal: 'tNormal', installment: 'tInstall', pix: 'tPix', debit: 'tDebit', boleto: 'tBoleto', cash: 'tBoleto' };
  const el = document.getElementById(map[t]);
  if (el) el.classList.add('active');
  const installGroup = document.getElementById('installGroup');
  installGroup.style.display = t === 'installment' ? 'block' : 'none';
  updateInstallHint();
}

function setOwner(o) {
  S.entryOwner = o;
  document.getElementById('tMine').classList.toggle('active', o === 'mine');
  document.getElementById('tOther').classList.toggle('active', o === 'other');
  document.getElementById('tSplit').classList.toggle('active', o === 'split');
  document.getElementById('personGroup').style.display = o === 'other' ? 'block' : 'none';
  document.getElementById('splitGroup').style.display = o === 'split' ? 'block' : 'none';
  if (o === 'split') {
    if (!S.splitPeople) S.splitPeople = [];
    if (!S.splitCount || S.splitCount < 2) S.splitCount = 2;
    while (S.splitPeople.length < S.splitCount - 1) S.splitPeople.push('');
    S.splitPeople = S.splitPeople.slice(0, S.splitCount - 1);
    document.getElementById('splitCountVal').textContent = S.splitCount;
    // Restaura estado de porcentagem personalizada
    const cb = document.getElementById('splitCustomPct');
    if (cb) cb.checked = S.splitCustomPct || false;
    const pctRow = document.getElementById('splitPctRow');
    if (pctRow) pctRow.style.display = S.splitCustomPct ? 'block' : 'none';
    if (S.splitCustomPct && S.splitMyPct) {
      const pctIn = document.getElementById('splitMyPct');
      if (pctIn) pctIn.value = S.splitMyPct;
    }
    renderSplitNamesContainer();
    updateSplitHint();
  }
}

function adjustSplitCount(delta) {
  S.splitCount = Math.max(2, (S.splitCount || 2) + delta);
  if (!S.splitPeople) S.splitPeople = [];
  while (S.splitPeople.length < S.splitCount - 1) S.splitPeople.push('');
  S.splitPeople = S.splitPeople.slice(0, S.splitCount - 1);
  document.getElementById('splitCountVal').textContent = S.splitCount;
  renderSplitNamesContainer();
  updateSplitHint();
}

function renderSplitNamesContainer() {
  const wrap = document.getElementById('splitNamesWrap');
  if (!wrap) return;
  const known = getAllPeople();
  const count = S.splitCount || 2;
  const people = S.splitPeople || [];

  // Monta HTML dos campos de nome (sem onclick inline)
  const fieldsHtml = Array.from({ length: count - 1 }, (_, i) => {
    const val = (people[i] || '').replace(/"/g, '&quot;');
    return `<div class="fg" style="margin-bottom:6px;position:relative" data-split-field="${i}">
      <input type="text" placeholder="Nome da pessoa ${i + 1}" value="${val}"
        data-split-idx="${i}"
        style="padding-right:${val ? 28 : 10}px">
      ${val ? `<button type="button" data-split-clear="${i}"
        style="position:absolute;right:8px;top:50%;transform:translateY(-50%);background:none;border:none;
        color:var(--text3);cursor:pointer;font-size:16px;padding:0;line-height:1">×</button>` : ''}
    </div>`;
  }).join('');

  wrap.innerHTML =
    (known.length ? `
      <div style="font-size:11px;color:var(--text3);margin-bottom:5px">Pessoas já cadastradas — clique para preencher:</div>
      <div class="chips" id="splitKnownChips" style="margin-bottom:12px"></div>` : '') +
    fieldsHtml;

  // Chips: event listeners (evita problemas de escaping com qualquer nome)
  const chipsDiv = document.getElementById('splitKnownChips');
  if (chipsDiv) {
    known.forEach(p => {
      const chip = document.createElement('div');
      chip.className = 'chip';
      chip.textContent = p;
      chip.addEventListener('click', () => fillSplitName(p));
      chipsDiv.appendChild(chip);
    });
  }

  // Inputs: atualizam S.splitPeople sem re-renderizar
  wrap.querySelectorAll('input[data-split-idx]').forEach(inp => {
    const idx = parseInt(inp.dataset.splitIdx);
    inp.addEventListener('input', () => { S.splitPeople[idx] = inp.value; updateSplitHint(); });
  });

  // Botões ×: limpam campo e re-renderizam
  wrap.querySelectorAll('button[data-split-clear]').forEach(btn => {
    const idx = parseInt(btn.dataset.splitClear);
    btn.addEventListener('click', () => clearSplitPerson(idx));
  });
}

function fillSplitName(name) {
  if (!S.splitPeople) S.splitPeople = [];
  const emptyIdx = S.splitPeople.findIndex(p => !p);
  if (emptyIdx >= 0) {
    S.splitPeople[emptyIdx] = name;
  } else {
    return; // all fields already filled
  }
  renderSplitNamesContainer();
  updateSplitHint();
}

function clearSplitPerson(i) {
  if (S.splitPeople) S.splitPeople[i] = '';
  renderSplitNamesContainer();
  updateSplitHint();
}

function toggleSplitCustomPct(checked) {
  S.splitCustomPct = checked;
  if (!checked) S.splitMyPct = null;
  const pctRow = document.getElementById('splitPctRow');
  if (pctRow) pctRow.style.display = checked ? 'block' : 'none';
  if (!checked) {
    const pctIn = document.getElementById('splitMyPct');
    if (pctIn) pctIn.value = '';
  }
  updateSplitHint();
}

function updateSplitHint() {
  if (S.entryOwner !== 'split') return;
  const hint = document.getElementById('splitHint');
  if (!hint) return;
  const count = S.splitCount || 2;
  const people = (S.splitPeople || []).filter(Boolean);
  const amt = parseFloat(document.getElementById('eAmt')?.value) || 0;

  // Calcula partes
  const myRatio = (S.splitCustomPct && S.splitMyPct) ? S.splitMyPct / 100 : 1 / count;
  const myAmt = amt * myRatio;
  const othersTotal = amt * (1 - myRatio);
  const eachOther = count > 1 ? othersTotal / (count - 1) : 0;

  if (amt <= 0) {
    hint.textContent = `Dividindo entre ${count} pessoa${count > 1 ? 's' : ''} · informe o valor acima`;
    return;
  }
  const lines = [`<span style="color:var(--accent)">Eu: R$ ${fmt(myAmt)}</span>`];
  people.forEach(p => lines.push(`<span style="color:var(--blue)">${p}: R$ ${fmt(eachOther)}</span>`));
  const unnamed = count - 1 - people.length;
  for (let i = 0; i < unnamed; i++) lines.push(`<span style="color:var(--text3)">Pessoa ${people.length + i + 1}: R$ ${fmt(eachOther)}</span>`);
  hint.innerHTML = `<span style="color:var(--text3)">÷${count} ·</span> ${lines.join(' · ')}`;
}

// ── Categorias pré-definidas com ícones ──
const DEFAULT_CATS = [
  { icon: '🛒', label: 'Mercado' },
  { icon: '🍽️', label: 'Alimentação' },
  { icon: '🚗', label: 'Transporte' },
  { icon: '💊', label: 'Saúde' },
  { icon: '📱', label: 'Internet/Celular' },
  { icon: '🏠', label: 'Moradia' },
  { icon: '📚', label: 'Educação' },
  { icon: '🎬', label: 'Lazer' },
  { icon: '👕', label: 'Roupas' },
  { icon: '⛽', label: 'Combustível' },
  { icon: '🐾', label: 'Pet' },
  { icon: '✈️', label: 'Viagem' },
  { icon: '🎁', label: 'Presentes' },
  { icon: '💻', label: 'Eletrônicos' },
  { icon: '📦', label: 'Outros' },
];

function renderCatChips(selectedCat) {
  const wrap = document.getElementById('catChips');
  if (!wrap) return;
  const custom = JSON.parse(localStorage.getItem('fin_custom_cats') || '[]');
  const all = [...DEFAULT_CATS, ...custom.map(c => ({ icon: '🏷️', label: c }))];
  wrap.innerHTML = all.map(c =>
    `<div class="chip${selectedCat === c.label ? ' sel' : ''}" data-cat="${c.label}" onclick="pickCat(this)">${c.icon} ${c.label}</div>`
  ).join('') + `<div class="chip chip-add" onclick="_addCustomCat()" style="border-style:dashed;opacity:.7">+ categoria</div>`;
}

function pickCat(el) {
  document.querySelectorAll('#catChips .chip').forEach(c => c.classList.remove('sel'));
  el.classList.add('sel');
  document.getElementById('eCat').value = el.dataset.cat || el.textContent.trim();
}

function _addCustomCat() {
  const name = prompt('Nome da nova categoria:');
  if (!name || !name.trim()) return;
  const label = name.trim();
  const custom = JSON.parse(localStorage.getItem('fin_custom_cats') || '[]');
  if (!custom.includes(label)) {
    custom.push(label);
    localStorage.setItem('fin_custom_cats', JSON.stringify(custom));
  }
  renderCatChips(label);
  document.getElementById('eCat').value = label;
  // Marca o chip recém-criado como selecionado
  document.querySelectorAll('#catChips .chip').forEach(c => {
    if (c.dataset.cat === label) c.classList.add('sel');
  });
}

function renderPersonChips() {
  const pp = getAllPeople();
  document.getElementById('personChips').innerHTML = pp.map(p =>
    `<div class="chip" onclick="document.getElementById('ePerson').value='${p}'">${p}</div>`
  ).join('');
}

// ── Hint dinâmico: mostra valor por parcela e divisão em tempo real ──
function updateInstallHint() {
  if (S.entryOwner === 'split') updateSplitHint();

  const hint = document.getElementById('installHint');
  if (!hint) return;

  if (S.entryType !== 'installment') {
    hint.style.display = 'none';
    return;
  }

  const total = parseInt(document.getElementById('eInstTotal')?.value) || 0;
  const amt = parseFloat(document.getElementById('eAmt')?.value) || 0;

  if (total >= 2 && amt > 0) {
    const parcel = amt / total;
    hint.style.display = 'block';
    hint.innerHTML = `→ <span style="color:var(--accent)">${total}x de R$ ${fmt(parcel)}</span> por mês`;
  } else {
    hint.style.display = 'none';
  }
}

async function saveEntry() {
  const desc = document.getElementById('eDesc').value.trim();
  const amtRaw = parseFloat(document.getElementById('eAmt').value);
  const date = document.getElementById('eDate').value;
  const bankName = document.getElementById('eBank').value;
  const splitCount = S.entryOwner === 'split' ? (S.splitCount || 2) : null;
  const splitPeople = S.entryOwner === 'split' ? (S.splitPeople || []).filter(Boolean).map(normalizeName) : [];
  const person = S.entryOwner === 'other'
    ? normalizeName(document.getElementById('ePerson').value)
    : S.entryOwner === 'split'
      ? splitPeople.join(', ')
      : null;
  const splitRatio = S.entryOwner === 'split'
    ? ((S.splitCustomPct && S.splitMyPct) ? S.splitMyPct / 100 : 1 / (splitCount || 2))
    : null;
  const cat = document.getElementById('eCat').value.trim() || null;
  const note = document.getElementById('eNote').value.trim() || null;
  const type = S.entryType;
  const editId = document.getElementById('editEntryId').value;
  const editBank = document.getElementById('editBankName').value;

  if (!desc || isNaN(amtRaw) || amtRaw <= 0) { alert('Preencha descrição e valor.'); return; }
  if (S.entryOwner === 'other' && !person) { alert('Informe o nome da pessoa.'); return; }
  if (S.entryOwner === 'split' && splitPeople.length === 0) { alert('Informe ao menos um nome para dividir.'); return; }

  const m = getMonth();
  const bank = m.banks.find(b => b.name === bankName);
  if (!bank) { alert('Banco não encontrado. Selecione um banco válido.'); return; }

  if (editId && editBank) {
    const oldBank = m.banks.find(b => b.name === editBank);
    if (oldBank) oldBank.entries = oldBank.entries.filter(e => String(e.id) !== String(editId));
    await dbDeleteEntry(editId);
  }

  setSyncing(true);

if (type === 'installment') {
  const total = parseInt(document.getElementById('eInstTotal').value) || 0;
  const cur = parseInt(document.getElementById('eInstCur').value) || 1;
  if (total < 2) { alert('Informe o total de parcelas.'); setSyncing(false); return; }
  if (cur > total) { alert(`Parcela atual (${cur}) não pode ser maior que o total (${total}).`); setSyncing(false); return; }

  const partAmt = parseFloat((amtRaw / total).toFixed(2));
  const gId = editId ? ('grp_' + editId) : 'grp_' + Date.now();

  // ── Se é edição de parcelado, pergunta sobre bulk update ──
  if (editId) {
    const entry = {
      id: editId, desc, amount: partAmt, date,
      owner: S.entryOwner, person,
      splitPeople: S.entryOwner === 'split' ? splitPeople : null,
      splitCount: S.entryOwner === 'split' ? splitCount : null,
      splitRatio: S.entryOwner === 'split' ? splitRatio : null,
      category: cat, note,
      type: 'installment', installCurrent: cur, installTotal: total, groupId: gId
    };
    bank.entries.push(entry);
    await dbSaveEntry(m.key, bankName, entry);

    const applyAll = confirm('Deseja aplicar esta alteração em TODAS as parcelas (passadas e futuras)?\n\nOK = Todas as parcelas\nCancelar = Apenas esta');
    if (applyAll) {
      await bulkUpdateInstallments(gId, bankName, desc, partAmt, cat, note);
    }
  } else {
    // Novo lançamento parcelado
    const entry = {
      id: Date.now(), desc, amount: partAmt, date,
      owner: S.entryOwner, person,
      splitPeople: S.entryOwner === 'split' ? splitPeople : null,
      splitCount: S.entryOwner === 'split' ? splitCount : null,
      splitRatio: S.entryOwner === 'split' ? splitRatio : null,
      category: cat, note,
      type: 'installment', installCurrent: cur, installTotal: total, groupId: gId
    };
    bank.entries.push(entry);
    await dbSaveEntry(m.key, bankName, entry);
    await registerFutureInst({
      desc, partAmt, total, cur, bankName,
      owner: S.entryOwner, person, cat, gId,
      startKey: S.currentMonth, date
    });
  }
} else {
  // ── Lançamento normal, pix ou dividido ──
  const entry = {
    id: editId ? String(editId) : String(Date.now()),
    desc, amount: amtRaw, date,
    owner: S.entryOwner, person,
    splitPeople: S.entryOwner === 'split' ? splitPeople : null,
    splitCount: S.entryOwner === 'split' ? splitCount : null,
    splitRatio,
    category: cat, note,
    type, installCurrent: null, installTotal: null, groupId: null
  };
  bank.entries.push(entry);
  await dbSaveEntry(m.key, bankName, entry);
}
  setSyncing(false);
  renderDash();
  closeModal('mEntry');
  showToast('✓ Lançamento salvo');
}

async function deleteEntry(bankName, id) {
  if (!confirm('Excluir lançamento?')) return;
  const m = getMonth();
  const bk = m.banks.find(b => b.name === bankName);
  const en = bk?.entries.find(e => String(e.id) === String(id));
  setSyncing(true);
  if (en?.groupId && confirm('Cancelar parcelas futuras também?')) await cancelInst(en.groupId, false);
  if (bk) bk.entries = bk.entries.filter(e => String(e.id) !== String(id));
  await dbDeleteEntry(id);
  setSyncing(false);
  renderDash();
  closeModal('mDetail');
  showToast('Lançamento excluído');
}

function showEntryDetail(entry, bankName) {
  const color = PALETTE[S.months.find(x => x.key === S.currentMonth)?.banks.find(b => b.name === bankName)?.color] || '#4d9fff';
  let html = `
    <div class="detail-header">
      <div>
        <div class="detail-desc">${entry.desc}</div>
        <div style="font-size:12px;color:var(--text3);font-family:var(--mono)">${bankName}</div>
      </div>
      <div class="detail-amount" style="color:${color}">R$ ${fmt(entry.amount)}</div>
    </div>
    <div class="detail-grid">
      <div class="detail-item">
        <div class="detail-item-label">Data</div>
        <div class="detail-item-val">${fmtDateLong(entry.date)}</div>
      </div>
      <div class="detail-item">
        <div class="detail-item-label">De quem</div>
        <div class="detail-item-val">${
          entry.owner === 'split'
            ? `Dividido com ${(entry.splitPeople || (entry.person ? [entry.person] : [])).filter(Boolean).join(', ')}`
            : entry.owner === 'other' ? entry.person : 'Meu'
        }</div>
      </div>
      ${entry.owner === 'split' ? (() => {
        const count = entry.splitCount || ((entry.splitPeople?.length || 1) + 1);
        const share = entry.amount / count;
        const people = (entry.splitPeople || (entry.person ? entry.person.split(', ') : [])).filter(Boolean);
        const peopleStr = people.length ? people.join(', ') : 'outros';
        return `
      <div class="detail-item">
        <div class="detail-item-label">Minha parte (1/${count})</div>
        <div class="detail-item-val" style="color:var(--accent)">R$ ${fmt(share)}</div>
      </div>
      <div class="detail-item" style="grid-column:1/-1">
        <div class="detail-item-label">Cada um paga · ${peopleStr}</div>
        <div class="detail-item-val" style="color:var(--blue)">R$ ${fmt(share)} cada</div>
      </div>`;
      })() : ''}
      ${entry.category ? `
      <div class="detail-item">
        <div class="detail-item-label">Categoria</div>
        <div class="detail-item-val">${entry.category}</div>
      </div>` : ''}
      ${entry.type === 'installment' ? `
      <div class="detail-item">
        <div class="detail-item-label">Parcela</div>
        <div class="detail-item-val">${entry.installCurrent}/${entry.installTotal} · R$ ${fmt(entry.amount * entry.installTotal)} total</div>
      </div>` : ''}
      ${(entry.type === 'pix' || entry.type === 'debit' || entry.type === 'cash' || entry.type === 'boleto') ? `
      <div class="detail-item">
        <div class="detail-item-label">Tipo</div>
        <div class="detail-item-val">${entry.type === 'pix' ? 'Pix' : entry.type === 'debit' ? 'Débito' : entry.type === 'boleto' ? 'Boleto' : 'Dinheiro'}</div>
      </div>` : ''}
    </div>
    ${entry.note ? `<div class="note-box">${entry.note}</div>` : ''}`;

  document.getElementById('detailTitle').innerHTML = `Detalhes <button class="modal-close" onclick="closeModal('mDetail')">×</button>`;
  document.getElementById('detailContent').innerHTML = html;
  document.getElementById('detailActions').innerHTML = `
    <button class="btn btn-danger btn-sm" onclick="deleteEntry('${bankName}','${entry.id}')">🗑 Excluir</button>
    ${entry.type === 'installment' ? `
    <button class="btn btn-ghost btn-sm" style="color:var(--orange)"
      onclick="closeModal('mDetail');showInst(${JSON.stringify(entry).replace(/"/g, '&quot;')})">
      📦 Parcelas
    </button>` : ''}
    <button class="btn btn-primary btn-sm" onclick="closeModal('mDetail');openEntryM('${entry.id}','${bankName}')">✎ Editar</button>`;
  openModal('mDetail');
}

// ── Bulk Update: aplica edição em todas as parcelas do grupo ──
async function bulkUpdateInstallments(gId, bankName, newDesc, newAmt, newCat, newNote) {
  setSyncing(true);
  for (const m of S.months) {
    for (const b of m.banks) {
      for (const e of b.entries) {
        if (e.groupId === gId) {
          e.desc = newDesc;
          e.amount = newAmt;
          e.category = newCat;
          e.note = newNote;
          await dbSaveEntry(m.key, b.name, e);
        }
      }
    }
  }
  // Atualiza também os installments pendentes
  for (const inst of S.installments) {
    if (inst.gId === gId) {
      inst.desc = newDesc;
      inst.amount = newAmt;
      inst.cat = newCat;
      await dbSaveInstallment(inst);
    }
  }
  setSyncing(false);
}

/* ── js/installments.js ── */
// ══════════════════════════════════════════════════
// INSTALLMENTS.JS — Parcelas Futuras
// ══════════════════════════════════════════════════

async function registerFutureInst({desc, partAmt, total, cur, bankName, owner, person, cat, gId, startKey, date}) {
  // Limpa parcelas futuras antigas desse grupo
  await dbDeleteInstallmentsByGroup(gId);
  S.installments = S.installments.filter(i => i.gId !== gId);

  // Registra na tabela installments
  for (let p = cur + 1; p <= total; p++) {
    const inst = {
      id: 'i_' + Date.now() + '_' + p + '_' + Math.random().toString(36).slice(2, 7),
      gId, desc, amount: partAmt, total, partNum: p,
      bankName, owner, person, cat,
      offset: p - cur, startKey, date, done: false
    };
    S.installments.push(inst);
    await dbSaveInstallment(inst);
  }

  // ── INJETA nos meses que já existem ──
  const startIdx = S.months.findIndex(m => m.key === startKey);
  for (let p = cur + 1; p <= total; p++) {
    const targetIdx = startIdx + (p - cur);
    if (targetIdx >= S.months.length) break; // mês ainda não existe, tudo bem

    const targetMonth = S.months[targetIdx];

    // Evita duplicar se já foi injetado
    const jaExiste = targetMonth.banks
      .flatMap(b => b.entries)
      .some(e => e.groupId === gId && e.installCurrent === p);
    if (jaExiste) continue;

    // Acha ou cria o banco no mês destino
    let bk = targetMonth.banks.find(b => b.name === bankName);
    if (!bk) {
      const newBank = { name: bankName, color: 'azure', entries: [] };
      targetMonth.banks.push(newBank);
      await dbSaveBank(targetMonth.key, newBank);
      bk = targetMonth.banks[targetMonth.banks.length - 1];
    }

    // Cria a entrada da parcela
    const entry = {
      id: 'auto_' + Date.now() + '_' + p + '_' + Math.random(),
      desc, amount: partAmt, date,
      owner, person, category: cat,
      type: 'installment',
      installCurrent: p,
      installTotal: total,
      groupId: gId,
      autoInj: true
    };
    bk.entries.push(entry);
    await dbSaveEntry(targetMonth.key, bankName, entry);

    // Marca como done no installments
    const instRec = S.installments.find(i => i.gId === gId && i.partNum === p);
    if (instRec) {
      instRec.done = true;
      await dbMarkInstallmentDone(instRec.id);
    }
  }
}
async function injectInstallments(key) {
  const m = S.months.find(x => x.key === key);
  if (!m) return;
  const mIdx = S.months.findIndex(x => x.key === key);
  for (const inst of S.installments) {
    const si = S.months.findIndex(x => x.key === inst.startKey);
    if (si < 0 || si + inst.offset !== mIdx) continue;
    // Não injeta se já existe entrada com mesmo grupo e número de parcela
    const jaExiste = m.banks
      .flatMap(b => b.entries)
      .some(e => e.groupId === inst.gId && e.installCurrent === inst.partNum);
    if (jaExiste) continue;
    let bk = m.banks.find(b => b.name === inst.bankName);
    if (!bk) {
      const newBank = { name: inst.bankName, color: 'azure', entries: [] };
      m.banks.push(newBank);
      await dbSaveBank(key, newBank);
      bk = m.banks[m.banks.length - 1];
    }
    const entry = {
      id: 'auto_' + Date.now() + '_' + Math.random(),
      desc: inst.desc, amount: inst.amount, date: inst.date,
      owner: inst.owner, person: inst.person, category: inst.cat,
      type: 'installment', installCurrent: inst.partNum, installTotal: inst.total,
      groupId: inst.gId, autoInj: true
    };
    bk.entries.push(entry);
    await dbSaveEntry(key, inst.bankName, entry);
    await dbMarkInstallmentDone(inst.id);
    inst.done = true;
  }
}

async function cancelInst(gId, all) {
  setSyncing(true);
  const si = S.months.findIndex(m => m.key === S.currentMonth);
  for (const m of S.months) {
    const i = S.months.indexOf(m);
    if (all || i > si) {
      for (const b of m.banks) {
        const toDelete = b.entries.filter(e => e.groupId === gId && e.autoInj);
        for (const e of toDelete) await dbDeleteEntry(e.id);
        b.entries = b.entries.filter(e => !(e.groupId === gId && e.autoInj));
      }
    }
  }
  await dbDeleteInstallmentsByGroup(gId);
  S.installments = S.installments.filter(i => i.gId !== gId);
  setSyncing(false);
  renderDash();
  closeModal('mInstDet');
}

function showInst(e) {
  S._currentInstEntry = e;
  const maxAnt = (e.installTotal - e.installCurrent) - 1;

  const antSection = maxAnt >= 1 ? `
    <div style="margin-top:16px;padding-top:16px;border-top:1px solid var(--border)">
      <div class="card-lbl" style="margin-bottom:8px;text-transform:uppercase;letter-spacing:1px">Antecipar parcelas</div>
      <div style="display:flex;align-items:center;gap:10px;margin-bottom:10px">
        <input type="number" id="antN" min="1" max="${maxAnt}" value="1"
          class="modal-input" style="width:72px;text-align:center" oninput="updateAnticipatePreview()">
        <span style="font-size:12px;color:var(--text2)">de <strong>${maxAnt}</strong> possível${maxAnt !== 1 ? 'is' : ''}</span>
      </div>
      <div id="antPreview" style="font-size:12px;color:var(--text2);line-height:1.6"></div>
    </div>` : '';

  document.getElementById('instDetContent').innerHTML = `
    <div class="summary-grid" style="margin-bottom:0">
      <div class="card"><div class="card-lbl">Parcela</div><div class="card-val a">${e.installCurrent}/${e.installTotal}</div></div>
      <div class="card"><div class="card-lbl">Por parcela</div><div class="card-val">R$ ${fmt(e.amount)}</div></div>
      <div class="card"><div class="card-lbl">Total</div><div class="card-val">R$ ${fmt(e.amount * e.installTotal)}</div></div>
      <div class="card"><div class="card-lbl">Restam</div><div class="card-val o">${e.installTotal - e.installCurrent}x</div></div>
    </div>
    ${antSection}`;

  const antBtn = maxAnt >= 1
    ? `<button class="btn btn-primary btn-sm" onclick="confirmAnticipateParcelas()">Antecipar</button>`
    : '';

  document.getElementById('instDetActions').innerHTML = `
    <button class="btn btn-ghost btn-sm" onclick="closeModal('mInstDet')">Fechar</button>
    <button class="btn btn-ghost btn-sm" style="color:var(--orange)" onclick="cancelInst('${e.groupId}',false)">Cancelar próximas</button>
    <button class="btn btn-danger btn-sm" onclick="cancelInst('${e.groupId}',true)">Cancelar todas</button>
    ${antBtn}`;

  openModal('mInstDet');
  if (maxAnt >= 1) updateAnticipatePreview();
}

function updateAnticipatePreview() {
  const e = S._currentInstEntry;
  if (!e) return;
  const n = parseInt(document.getElementById('antN')?.value) || 0;
  const prev = document.getElementById('antPreview');
  if (!prev) return;
  if (n < 1) { prev.innerHTML = ''; return; }

  const cur = e.installCurrent;
  const total = e.installTotal;
  const gId = e.groupId;
  const newCur = cur + n;
  const si = S.months.findIndex(m => m.key === S.currentMonth);

  const affectedLabels = [];
  for (let i = si + 1; i < S.months.length; i++) {
    const m = S.months[i];
    const has = m.banks.some(b =>
      b.entries.some(x => x.groupId === gId && x.installCurrent > cur && x.installCurrent <= newCur)
    );
    if (has) affectedLabels.push(m.label);
  }

  let html = `Parcela atual: <strong>${cur}/${total}</strong> → <strong>${newCur}/${total}</strong>`;
  if (affectedLabels.length > 0) {
    html += `<br>Meses excluídos: <strong>${affectedLabels.join(', ')}</strong>`;
  }
  if (newCur < total) {
    html += `<br>Próxima restante: <strong>${newCur + 1}/${total}</strong>`;
  } else {
    html += `<br>Esta será a última parcela`;
  }
  prev.innerHTML = html;
}

async function confirmAnticipateParcelas() {
  const e = S._currentInstEntry;
  if (!e) return;
  const n = parseInt(document.getElementById('antN')?.value) || 0;
  const cur = e.installCurrent;
  const total = e.installTotal;
  const gId = e.groupId;
  const maxAnt = total - cur - 1;
  if (n < 1 || n > maxAnt) { showToast('Valor inválido para antecipação', 'error'); return; }

  const newCur = cur + n;
  setSyncing(true);

  // 1. Atualiza a parcela atual no mês corrente
  const si = S.months.findIndex(m => m.key === S.currentMonth);
  const curMonth = S.months[si];
  for (const b of curMonth.banks) {
    const found = b.entries.find(x => x.id === e.id);
    if (found) {
      found.installCurrent = newCur;
      await dbSaveEntry(S.currentMonth, b.name, found);
      break;
    }
  }

  // 2. Remove entradas intermediárias dos meses futuros
  for (let i = si + 1; i < S.months.length; i++) {
    const m = S.months[i];
    for (const b of m.banks) {
      const toDelete = b.entries.filter(x =>
        x.groupId === gId && x.installCurrent > cur && x.installCurrent <= newCur
      );
      for (const x of toDelete) await dbDeleteEntry(x.id);
      b.entries = b.entries.filter(x =>
        !(x.groupId === gId && x.installCurrent > cur && x.installCurrent <= newCur)
      );
    }
  }

  // 3. Remove registros de installments das parcelas puladas
  const toDeleteInst = S.installments.filter(i =>
    i.gId === gId && i.partNum > cur && i.partNum <= newCur
  );
  for (const inst of toDeleteInst) await dbDeleteInstallmentById(inst.id);
  S.installments = S.installments.filter(i =>
    !(i.gId === gId && i.partNum > cur && i.partNum <= newCur)
  );

  setSyncing(false);
  S._currentInstEntry = null;
  showToast('Parcelas antecipadas!', 'ok');
  closeModal('mInstDet');
  renderDash();
}

