// ── Banner "O que há de novo" ──────────────────────
function checkVersionBanner() {
  const seen = localStorage.getItem('fin_seen_version');
  if (seen === APP_VERSION) return;
  const el = document.getElementById('versionBanner');
  if (el) el.style.display = 'flex';
}

function dismissVersionBanner(openChangelog) {
  localStorage.setItem('fin_seen_version', APP_VERSION);
  const el = document.getElementById('versionBanner');
  if (el) el.style.display = 'none';
  if (openChangelog) showView('changelog');
}

// ── Render da view de changelog ────────────────────
function renderChangelog() {
  const el = document.getElementById('changelogContent');
  if (!el) return;

  const typeLabel = { feat: 'novo', fix: 'correção', improve: 'melhoria' };
  const typeColor = {
    feat:    { bg: 'rgba(77,159,255,.12)', text: 'var(--accent)',  border: 'rgba(77,159,255,.3)' },
    fix:     { bg: 'rgba(77,255,145,.1)',  text: 'var(--green)',   border: 'rgba(77,255,145,.25)' },
    improve: { bg: 'rgba(255,159,77,.1)',  text: 'var(--orange)',  border: 'rgba(255,159,77,.25)' },
  };

  // Usa entradas do Supabase se disponíveis, senão usa as hardcoded
  const source = (S.changelogEntries && S.changelogEntries.length > 0) ? S.changelogEntries : CHANGELOG;

  // Agrupar entradas com mesma versão em uma única "release"
  const releases = [];
  let lastVer = null;
  for (const entry of source) {
    if (entry.version !== lastVer) {
      releases.push({ version: entry.version, date: entry.date, groups: [] });
      lastVer = entry.version;
    }
    releases[releases.length - 1].groups.push(entry);
  }

  const header = `
    <div style="margin-bottom:28px;padding-bottom:20px;border-bottom:1px solid var(--border)">
      <div style="font-size:22px;font-weight:700;color:var(--text);margin-bottom:4px">O que há de novo ✨</div>
      <div style="font-size:13px;color:var(--text2)">Acompanhe as melhorias e correções de cada versão</div>
    </div>`;

  el.innerHTML = header + releases.map((rel, ri) => {
    const isLatest = ri === 0;

    const groups = rel.groups.map(g => {
      const rows = g.items.map(it => {
        const c = typeColor[it.type];
        return `
        <li style="display:flex;align-items:flex-start;gap:10px;padding:8px 0;border-bottom:1px solid var(--border)">
          <span style="flex-shrink:0;font-size:10px;font-family:var(--mono);padding:2px 8px;border-radius:20px;
            background:${c.bg};color:${c.text};border:1px solid ${c.border};margin-top:2px;white-space:nowrap;letter-spacing:.3px">
            ${typeLabel[it.type]}
          </span>
          <span style="font-size:13px;color:var(--text);line-height:1.5">${it.text}</span>
        </li>`;
      }).join('');

      return `
      <div style="margin-bottom:12px;background:var(--bg2);border:1px solid var(--border);border-radius:10px;overflow:hidden">
        <div style="padding:12px 16px 10px;border-bottom:1px solid var(--border)">
          <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:2px">${g.title}</div>
          <div style="font-size:12px;color:var(--text2);line-height:1.4">${g.summary}</div>
        </div>
        <ul style="list-style:none;margin:0;padding:0 16px">${rows}
          <li style="height:4px"></li>
        </ul>
      </div>`;
    }).join('');

    return `
    <div style="display:flex;gap:16px;margin-bottom:28px">
      <!-- Linha do tempo -->
      <div style="display:flex;flex-direction:column;align-items:center;padding-top:4px;flex-shrink:0">
        <div style="width:12px;height:12px;border-radius:50%;
          background:${isLatest ? 'var(--accent)' : 'var(--border2)'};
          box-shadow:${isLatest ? '0 0 0 3px rgba(77,159,255,.2)' : 'none'};
          flex-shrink:0"></div>
        ${ri < releases.length - 1 ? `<div style="flex:1;width:2px;background:var(--border);margin-top:4px;min-height:20px"></div>` : ''}
      </div>
      <!-- Conteúdo -->
      <div style="flex:1;min-width:0;padding-bottom:4px">
        <div style="display:flex;align-items:center;gap:8px;margin-bottom:12px">
          <span style="font-size:16px;font-weight:700;color:var(--text);font-family:var(--mono)">v${rel.version}</span>
          ${isLatest ? `<span style="font-size:10px;font-family:var(--mono);padding:2px 9px;border-radius:20px;background:var(--accent);color:#fff;letter-spacing:.3px">atual</span>` : ''}
          <span style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-left:auto">${rel.date}</span>
        </div>
        ${groups}
      </div>
    </div>`;
  }).join('');
}

/* ── js/dev.js ── */
// ══════════════════════════════════════════════════
// DEV.JS — Painel do Desenvolvedor
// Visível apenas para usuários em dev_users
// ══════════════════════════════════════════════════

let _devTab = 'changelog'; // 'changelog' | 'health' | 'users' | 'debug' | 'push' | 'devs' | 'app'

function renderDev() {
  const el = document.getElementById('devContent');
  if (!el || !S.isDev) return;
  if (_devTab === 'changelog') _renderDevChangelog(el);
  else if (_devTab === 'health') _renderDevHealth(el);
  else if (_devTab === 'users') _renderDevUsersManagement(el);
  else if (_devTab === 'debug') _renderDevDebug(el);
  else if (_devTab === 'push') _renderDevPush(el);
  else if (_devTab === 'devs') _renderDevUsers(el);
  else if (_devTab === 'app') _renderDevApp(el);
}

function _devTabBar() {
  const tabs = [
    { id: 'changelog', label: '📋 Novidades' },
    { id: 'health',    label: '📊 Saúde' },
    { id: 'users',     label: '👤 Usuários' },
    { id: 'debug',     label: '🔧 Debug' },
    { id: 'push',      label: '🔔 Push' },
    { id: 'devs',      label: '👥 Devs' },
    { id: 'app',       label: '⚙️ App' },
  ];
  return `
  <div style="overflow-x:auto;margin-bottom:20px;-webkit-overflow-scrolling:touch">
    <div style="display:flex;gap:4px;min-width:max-content;background:var(--bg2);border:1px solid var(--border);border-radius:8px;padding:4px">
      ${tabs.map(t => `
      <button onclick="_devSwitchTab('${t.id}')"
        style="padding:7px 12px;border-radius:6px;border:none;cursor:pointer;font-size:12px;font-weight:500;white-space:nowrap;transition:background .15s,color .15s;
          background:${_devTab===t.id ? 'var(--accent)' : 'transparent'};
          color:${_devTab===t.id ? '#fff' : 'var(--text2)'}">
        ${t.label}
      </button>`).join('')}
    </div>
  </div>`;
}

function _devSwitchTab(tab) {
  _devTab = tab;
  renderDev();
}

// ── RASCUNHOS (localStorage) ───────────────────────
function _devGetDrafts() {
  try { return JSON.parse(localStorage.getItem('fin_cl_drafts') || '[]'); } catch { return []; }
}
function _devSaveDrafts(drafts) {
  localStorage.setItem('fin_cl_drafts', JSON.stringify(drafts));
}

function _devAddDraft() {
  const typeEl = document.getElementById('devDraftType');
  const textEl = document.getElementById('devDraftText');
  const type = typeEl?.value || 'feat';
  const text = (textEl?.value || '').trim();
  if (!text) { showToast('Escreva o texto do item.', 'error'); return; }
  const drafts = _devGetDrafts();
  drafts.unshift({ id: Date.now().toString(), type, text });
  _devSaveDrafts(drafts);
  textEl.value = '';
  _devRenderDraftsList();
}

function _devDeleteDraft(id) {
  _devSaveDrafts(_devGetDrafts().filter(d => d.id !== id));
  _devRenderDraftsList();
}

function _devClearAllDrafts() {
  if (!confirm('Apagar todos os rascunhos?')) return;
  _devSaveDrafts([]);
  _devRenderDraftsList();
}

// Cor e label por tipo
function _draftBadge(type) {
  const map = {
    feat:    { bg: 'rgba(77,159,255,.15)', color: 'var(--accent)',  border: 'rgba(77,159,255,.3)',  label: 'feat' },
    fix:     { bg: 'rgba(77,255,145,.1)',  color: 'var(--green)',   border: 'rgba(77,255,145,.25)', label: 'fix' },
    improve: { bg: 'rgba(255,159,77,.1)',  color: 'var(--orange)',  border: 'rgba(255,159,77,.25)', label: 'melhoria' },
  };
  return map[type] || map.feat;
}

// Re-renderiza só a lista de rascunhos
function _devRenderDraftsList() {
  const el = document.getElementById('devDraftsList');
  if (!el) return;
  const drafts = _devGetDrafts();
  if (!drafts.length) {
    el.innerHTML = `<div style="font-size:12px;color:var(--text3);text-align:center;padding:10px 0">Nenhum rascunho ainda.</div>`;
    return;
  }
  el.innerHTML = drafts.map(d => {
    const b = _draftBadge(d.type);
    return `
    <div style="display:flex;align-items:center;gap:8px;padding:7px 0;border-bottom:1px solid var(--border)">
      <span style="font-size:10px;font-family:var(--mono);padding:2px 8px;border-radius:20px;background:${b.bg};color:${b.color};border:1px solid ${b.border};white-space:nowrap;flex-shrink:0">${b.label}</span>
      <span style="flex:1;font-size:12px;color:var(--text);line-height:1.4">${d.text}</span>
      <button onclick="_devDeleteDraft('${d.id}')"
        style="font-size:16px;line-height:1;background:none;border:none;color:var(--text3);cursor:pointer;padding:0 2px;flex-shrink:0" title="Remover">×</button>
    </div>`;
  }).join('');
}

// ── ABA: CHANGELOG ─────────────────────────────────
function _renderDevChangelog(el) {
  const entries = S.changelogEntries;
  const drafts  = _devGetDrafts();
  const announcements = S.announcements || [];

  const rows = entries.length
    ? entries.map(e => {
        const itemPreview = (e.items || []).slice(0, 2)
          .map(it => `<span style="font-size:11px;color:var(--text3)">• ${it.text}</span>`).join('<br>');
        const more = (e.items || []).length > 2
          ? `<span style="font-size:11px;color:var(--text3)">+${e.items.length - 2} itens...</span>` : '';
        return `
        <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:14px 16px;margin-bottom:10px">
          <div style="display:flex;align-items:flex-start;gap:10px;margin-bottom:8px">
            <div style="flex:1;min-width:0">
              <div style="display:flex;align-items:center;gap:8px;margin-bottom:2px">
                <span style="font-size:12px;font-family:var(--mono);color:var(--accent);font-weight:600">v${e.version}</span>
                <span style="font-size:11px;color:var(--text3);font-family:var(--mono)">${e.date}</span>
              </div>
              <div style="font-size:13px;font-weight:600;color:var(--text)">${e.title}</div>
              <div style="font-size:12px;color:var(--text2);margin-top:2px">${e.summary}</div>
              ${itemPreview || more ? `<div style="margin-top:6px;line-height:1.6">${itemPreview}${more ? '<br>' + more : ''}</div>` : ''}
            </div>
            <div style="display:flex;gap:6px;flex-shrink:0">
              <button onclick="_devEditEntry('${e.id}')"
                style="font-size:11px;padding:4px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer">Editar</button>
              <button onclick="_devDeleteEntry('${e.id}')"
                style="font-size:11px;padding:4px 10px;border-radius:6px;border:1px solid rgba(255,77,77,.3);background:rgba(255,77,77,.08);color:var(--red);cursor:pointer">Excluir</button>
            </div>
          </div>
        </div>`;
      }).join('')
    : `<div style="text-align:center;padding:32px;color:var(--text3);font-size:13px">Nenhuma entrada ainda.<br>Crie a primeira clicando em "+ Nova entrada".</div>`;

  // Lista de rascunhos
  const draftsHtml = drafts.length
    ? drafts.map(d => {
        const b = _draftBadge(d.type);
        return `
        <div style="display:flex;align-items:center;gap:8px;padding:7px 0;border-bottom:1px solid var(--border)">
          <span style="font-size:10px;font-family:var(--mono);padding:2px 8px;border-radius:20px;background:${b.bg};color:${b.color};border:1px solid ${b.border};white-space:nowrap;flex-shrink:0">${b.label}</span>
          <span style="flex:1;font-size:12px;color:var(--text);line-height:1.4">${d.text}</span>
          <button onclick="_devDeleteDraft('${d.id}')"
            style="font-size:16px;line-height:1;background:none;border:none;color:var(--text3);cursor:pointer;padding:0 2px;flex-shrink:0" title="Remover">×</button>
        </div>`;
      }).join('')
    : `<div style="font-size:12px;color:var(--text3);text-align:center;padding:10px 0">Nenhum rascunho ainda.</div>`;

  // Anúncios ativos
  const annRows = announcements.length
    ? announcements.map(a => `
      <div style="display:flex;align-items:center;gap:10px;padding:10px 14px;background:var(--bg2);border:1px solid var(--border);border-radius:8px;margin-bottom:8px">
        <div style="flex:1;min-width:0">
          <div style="font-size:12px;color:var(--text);line-height:1.5">${a.message}</div>
          <div style="font-size:10px;color:var(--text3);font-family:var(--mono);margin-top:2px">${new Date(a.createdAt).toLocaleDateString('pt-BR')}</div>
        </div>
        <button onclick="_devToggleAnnouncement('${a.id}', ${!a.active})"
          style="font-size:11px;padding:4px 10px;border-radius:20px;border:1px solid ${a.active ? 'rgba(77,255,145,.3)' : 'var(--border2)'};background:${a.active ? 'rgba(77,255,145,.1)' : 'var(--bg3)'};color:${a.active ? 'var(--green)' : 'var(--text3)'};cursor:pointer;white-space:nowrap;flex-shrink:0">
          ${a.active ? '● Ativo' : '○ Inativo'}
        </button>
        <button onclick="_devDeleteAnnouncement('${a.id}')"
          style="font-size:11px;padding:4px 10px;border-radius:6px;border:1px solid rgba(255,77,77,.3);background:rgba(255,77,77,.08);color:var(--red);cursor:pointer;flex-shrink:0">Excluir</button>
      </div>`)
      .join('')
    : `<div style="font-size:12px;color:var(--text3);padding:10px 0 4px">Nenhum anúncio ainda.</div>`;

  el.innerHTML = `
    ${_devTabBar()}

    <!-- Rascunhos -->
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:14px 16px;margin-bottom:20px">
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:6px">
        <div>
          <div style="font-size:13px;font-weight:600;color:var(--text)">💡 Rascunhos</div>
          <div style="font-size:11px;color:var(--text3);margin-top:2px">Anote mudanças conforme você desenvolve. Na hora de criar uma entrada, você escolhe quais incluir.</div>
        </div>
        ${drafts.length ? `<button onclick="_devClearAllDrafts()" style="font-size:11px;padding:3px 10px;border-radius:6px;border:1px solid rgba(255,77,77,.3);background:rgba(255,77,77,.06);color:var(--red);cursor:pointer;flex-shrink:0">Limpar tudo</button>` : ''}
      </div>
      <div style="display:flex;gap:8px;margin-bottom:10px;margin-top:10px">
        <select id="devDraftType"
          style="padding:7px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:12px;font-family:var(--mono);cursor:pointer">
          <option value="feat">feat</option>
          <option value="fix">fix</option>
          <option value="improve">improve</option>
        </select>
        <input id="devDraftText" type="text" placeholder="Descreva a mudança..."
          style="flex:1;padding:7px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px"
          onkeydown="if(event.key==='Enter')_devAddDraft()">
        <button onclick="_devAddDraft()"
          style="padding:7px 14px;border-radius:6px;background:var(--accent);color:#fff;border:none;cursor:pointer;font-size:13px;font-weight:500;white-space:nowrap">+ Anotar</button>
      </div>
      <div id="devDraftsList">${draftsHtml}</div>
    </div>

    <!-- Anúncios ativos -->
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:14px 16px;margin-bottom:20px">
      <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:10px">📣 Anúncios / Notificações</div>
      <div id="devAnnouncementsList">${annRows}</div>
    </div>

    <!-- Entradas do changelog -->
    <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:16px">
      <div>
        <div style="font-size:15px;font-weight:600;color:var(--text)">Entradas do changelog</div>
        <div style="font-size:12px;color:var(--text3)">${entries.length} entrada(s) · ordenadas por mais recente</div>
      </div>
      <button onclick="_devNewEntry()"
        style="font-size:12px;padding:6px 14px;border-radius:7px;background:var(--accent);color:#fff;border:none;cursor:pointer;font-weight:500">+ Nova entrada</button>
    </div>
    <div id="devChangelogForm" style="display:none"></div>
    ${rows}`;
}

function _devNewEntry() { _devShowForm(null); }
function _devEditEntry(id) {
  const entry = S.changelogEntries.find(e => e.id === id);
  if (entry) _devShowForm(entry);
}

function _devShowForm(entry) {
  const el = document.getElementById('devChangelogForm');
  if (!el) return;
  el.style.display = 'block';

  const itemsText = (entry?.items || []).map(it => `${it.type}: ${it.text}`).join('\n');
  const maxPos = S.changelogEntries.length
    ? Math.max(...S.changelogEntries.map(e => e.position || 0)) : 0;
  const drafts = _devGetDrafts();

  // HTML dos rascunhos com checkbox
  const draftsCheckboxHtml = drafts.length
    ? `
      <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:8px">
        <span style="font-size:11px;color:var(--text2);font-weight:600">Selecione os rascunhos a incluir:</span>
        <div style="display:flex;gap:6px">
          <button onclick="_devSelectAllDrafts(true)" style="font-size:11px;padding:2px 8px;border-radius:4px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer">Todos</button>
          <button onclick="_devSelectAllDrafts(false)" style="font-size:11px;padding:2px 8px;border-radius:4px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer">Nenhum</button>
        </div>
      </div>
      <div id="devDraftCheckboxes" style="display:flex;flex-direction:column;gap:4px;max-height:200px;overflow-y:auto">
        ${drafts.map(d => {
          const b = _draftBadge(d.type);
          return `
          <label style="display:flex;align-items:center;gap:8px;padding:6px 8px;border-radius:6px;background:var(--bg);border:1px solid var(--border);cursor:pointer">
            <input type="checkbox" class="dev-draft-cb" data-id="${d.id}" data-type="${d.type}" data-text="${d.text.replace(/"/g,'&quot;')}" checked
              style="width:14px;height:14px;accent-color:var(--accent);flex-shrink:0;cursor:pointer">
            <span style="font-size:10px;font-family:var(--mono);padding:1px 7px;border-radius:20px;background:${b.bg};color:${b.color};border:1px solid ${b.border};white-space:nowrap;flex-shrink:0">${b.label}</span>
            <span style="font-size:12px;color:var(--text);line-height:1.4;flex:1">${d.text}</span>
          </label>`;
        }).join('')}
      </div>
      <button onclick="_devAddCheckedDraftsToItems()"
        style="margin-top:10px;width:100%;padding:7px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer;font-size:12px;font-weight:500">
        ↓ Adicionar selecionados ao campo de itens
      </button>`
    : `<div style="font-size:12px;color:var(--text3);text-align:center;padding:8px 0">Nenhum rascunho para incluir. Anote rascunhos acima.</div>`;

  el.innerHTML = `
  <div style="background:var(--bg2);border:1px solid var(--accent);border-radius:10px;padding:16px;margin-bottom:16px">
    <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:14px">${entry ? 'Editar entrada' : 'Nova entrada'}</div>
    <input type="hidden" id="devEntryId" value="${entry?.id || ''}">
    <input type="hidden" id="devEntryPos" value="${entry?.position ?? (maxPos + 1)}">
    <div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:10px">
      <div>
        <label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px">Versão</label>
        <input id="devEntryVersion" type="text" value="${entry?.version || ''}" placeholder="ex: 1.2"
          style="width:100%;box-sizing:border-box;padding:7px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px">
      </div>
      <div>
        <label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px">Data</label>
        <input id="devEntryDate" type="text" value="${entry?.date || ''}" placeholder="ex: Maio 2026"
          style="width:100%;box-sizing:border-box;padding:7px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px">
      </div>
    </div>
    <div style="margin-bottom:10px">
      <label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px">Título</label>
      <input id="devEntryTitle" type="text" value="${(entry?.title || '').replace(/"/g,'&quot;')}" placeholder="ex: Melhorias no import IA"
        style="width:100%;box-sizing:border-box;padding:7px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px">
    </div>
    <div style="margin-bottom:10px">
      <label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px">Resumo</label>
      <input id="devEntrySummary" type="text" value="${(entry?.summary || '').replace(/"/g,'&quot;')}" placeholder="Uma frase descrevendo o grupo"
        style="width:100%;box-sizing:border-box;padding:7px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px">
    </div>

    <!-- Rascunhos com checkboxes -->
    <div style="background:var(--bg3);border:1px solid var(--border);border-radius:8px;padding:12px 14px;margin-bottom:10px">
      <div style="font-size:11px;font-weight:600;color:var(--text2);margin-bottom:10px">💡 Rascunhos disponíveis</div>
      ${draftsCheckboxHtml}
    </div>

    <div style="margin-bottom:10px">
      <label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px">
        Itens — uma por linha: <span style="font-family:var(--mono)">feat: texto</span> / <span style="font-family:var(--mono)">fix: texto</span> / <span style="font-family:var(--mono)">improve: texto</span>
      </label>
      <textarea id="devEntryItems" rows="6" placeholder="feat: Nova funcionalidade X&#10;fix: Corrigido bug Y&#10;improve: Melhoria em Z"
        style="width:100%;box-sizing:border-box;padding:8px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:12px;font-family:var(--mono);resize:vertical;line-height:1.6">${itemsText}</textarea>
    </div>

    <!-- Toggle notificação -->
    <div style="display:flex;align-items:center;gap:12px;padding:12px 14px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;margin-bottom:14px">
      <div style="flex:1">
        <div style="font-size:13px;font-weight:500;color:var(--text)">📣 Notificar usuários</div>
        <div style="font-size:11px;color:var(--text3);margin-top:2px">Exibe um banner para todos os usuários no próximo acesso</div>
      </div>
      <label style="display:flex;align-items:center;gap:8px;cursor:pointer">
        <input type="checkbox" id="devEntryNotify" ${!entry ? 'checked' : ''}
          style="width:16px;height:16px;accent-color:var(--accent);cursor:pointer">
        <span id="devEntryNotifyLabel" style="font-size:12px;font-family:var(--mono);color:var(--text3)">${!entry ? 'Sim' : 'Não'}</span>
      </label>
    </div>

    <div style="display:flex;gap:8px;justify-content:flex-end">
      <button onclick="_devCancelForm()" style="padding:7px 16px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer;font-size:13px">Cancelar</button>
      <button onclick="_devSaveForm()" style="padding:7px 18px;border-radius:6px;background:var(--accent);color:#fff;border:none;cursor:pointer;font-size:13px;font-weight:500">Salvar entrada</button>
    </div>
  </div>`;

  // Atualiza label do toggle ao mudar
  const notifyCb = document.getElementById('devEntryNotify');
  const notifyLabel = document.getElementById('devEntryNotifyLabel');
  if (notifyCb && notifyLabel) {
    notifyCb.addEventListener('change', () => {
      notifyLabel.textContent = notifyCb.checked ? 'Sim' : 'Não';
    });
  }

  el.scrollIntoView({ behavior: 'smooth', block: 'start' });
}

function _devSelectAllDrafts(checked) {
  document.querySelectorAll('.dev-draft-cb').forEach(cb => cb.checked = checked);
}

function _devAddCheckedDraftsToItems() {
  const checkboxes = document.querySelectorAll('.dev-draft-cb:checked');
  if (!checkboxes.length) { showToast('Nenhum rascunho selecionado.', 'error'); return; }
  const ta = document.getElementById('devEntryItems');
  if (!ta) return;
  const lines = [];
  checkboxes.forEach(cb => {
    lines.push(`${cb.dataset.type}: ${cb.dataset.text}`);
  });
  const cur = ta.value.trimEnd();
  ta.value = cur ? cur + '\n' + lines.join('\n') : lines.join('\n');
  showToast(`${lines.length} item(s) adicionado(s)`);
}

function _devCancelForm() {
  const el = document.getElementById('devChangelogForm');
  if (el) { el.style.display = 'none'; el.innerHTML = ''; }
}

async function _devSaveForm() {
  const id      = document.getElementById('devEntryId').value.trim() || null;
  const pos     = parseInt(document.getElementById('devEntryPos').value) || 0;
  const version = document.getElementById('devEntryVersion').value.trim();
  const date    = document.getElementById('devEntryDate').value.trim();
  const title   = document.getElementById('devEntryTitle').value.trim();
  const summary = document.getElementById('devEntrySummary').value.trim();
  const rawItems = document.getElementById('devEntryItems').value;
  const notify  = document.getElementById('devEntryNotify')?.checked ?? false;

  if (!version || !date || !title || !summary) { showToast('Preencha versão, data, título e resumo.', 'error'); return; }

  const typeMap = { feat: 'feat', fix: 'fix', improve: 'improve', melhoria: 'improve', correção: 'fix', novo: 'feat' };
  const items = rawItems.split('\n').map(l => l.trim()).filter(Boolean).map(l => {
    const sep = l.indexOf(':');
    if (sep < 0) return { type: 'feat', text: l };
    const rawType = l.slice(0, sep).trim().toLowerCase();
    return { type: typeMap[rawType] || 'feat', text: l.slice(sep + 1).trim() };
  });

  setSyncing(true);

  // Salva o changelog entry
  const saved = await dbSaveChangelogEntry({ id, version, date, title, summary, items, position: pos });

  // Salva anúncio se notificação ativada (apenas para entradas novas ou se marcou)
  if (notify && saved) {
    const msg = `🚀 Nova atualização v${version}: ${title}. Veja o que há de novo em "Novidades"!`;
    const ann = await dbSaveAnnouncement(msg);
    if (ann) {
      S.announcements.unshift(ann);
      renderAnnouncementBanner();
    }
  }

  setSyncing(false);

  if (!saved) { showToast('Erro ao salvar.', 'error'); return; }

  if (id) {
    const idx = S.changelogEntries.findIndex(e => e.id === id);
    if (idx >= 0) S.changelogEntries[idx] = saved;
  } else {
    S.changelogEntries.unshift(saved);
    S.changelogEntries.sort((a, b) => (b.position || 0) - (a.position || 0));
  }

  // Remove rascunhos usados (os que estavam marcados)
  const usedIds = Array.from(document.querySelectorAll('.dev-draft-cb:checked')).map(cb => cb.dataset.id);
  if (usedIds.length) {
    _devSaveDrafts(_devGetDrafts().filter(d => !usedIds.includes(d.id)));
  }

  _devCancelForm();
  renderDev();
  showToast(notify ? '✓ Entrada salva + notificação enviada' : '✓ Entrada salva');
}

async function _devDeleteEntry(id) {
  if (!confirm('Excluir esta entrada do changelog?')) return;
  setSyncing(true);
  await dbDeleteChangelogEntry(id);
  setSyncing(false);
  S.changelogEntries = S.changelogEntries.filter(e => e.id !== id);
  renderDev();
  showToast('Entrada excluída');
}

// ── Anúncios ───────────────────────────────────────
async function _devToggleAnnouncement(id, active) {
  setSyncing(true);
  const ok = await dbToggleAnnouncement(id, active);
  setSyncing(false);
  if (!ok) { showToast('Erro ao atualizar anúncio.', 'error'); return; }
  const ann = S.announcements.find(a => a.id === id);
  if (ann) ann.active = active;
  renderAnnouncementBanner();
  _renderAnnouncementsSection();
  showToast(active ? 'Anúncio ativado' : 'Anúncio desativado');
}

async function _devDeleteAnnouncement(id) {
  if (!confirm('Excluir este anúncio?')) return;
  setSyncing(true);
  await dbDeleteAnnouncement(id);
  setSyncing(false);
  S.announcements = S.announcements.filter(a => a.id !== id);
  renderAnnouncementBanner();
  _renderAnnouncementsSection();
  showToast('Anúncio excluído');
}

function _renderAnnouncementsSection() {
  const el = document.getElementById('devAnnouncementsList');
  if (!el) return;
  const announcements = S.announcements || [];
  if (!announcements.length) {
    el.innerHTML = `<div style="font-size:12px;color:var(--text3);padding:10px 0 4px">Nenhum anúncio ainda.</div>`;
    return;
  }
  el.innerHTML = announcements.map(a => `
    <div style="display:flex;align-items:center;gap:10px;padding:10px 14px;background:var(--bg2);border:1px solid var(--border);border-radius:8px;margin-bottom:8px">
      <div style="flex:1;min-width:0">
        <div style="font-size:12px;color:var(--text);line-height:1.5">${a.message}</div>
        <div style="font-size:10px;color:var(--text3);font-family:var(--mono);margin-top:2px">${new Date(a.createdAt).toLocaleDateString('pt-BR')}</div>
      </div>
      <button onclick="_devToggleAnnouncement('${a.id}', ${!a.active})"
        style="font-size:11px;padding:4px 10px;border-radius:20px;border:1px solid ${a.active ? 'rgba(77,255,145,.3)' : 'var(--border2)'};background:${a.active ? 'rgba(77,255,145,.1)' : 'var(--bg3)'};color:${a.active ? 'var(--green)' : 'var(--text3)'};cursor:pointer;white-space:nowrap;flex-shrink:0">
        ${a.active ? '● Ativo' : '○ Inativo'}
      </button>
      <button onclick="_devDeleteAnnouncement('${a.id}')"
        style="font-size:11px;padding:4px 10px;border-radius:6px;border:1px solid rgba(255,77,77,.3);background:rgba(255,77,77,.08);color:var(--red);cursor:pointer;flex-shrink:0">Excluir</button>
    </div>`).join('');
}

// ── ABA: SAÚDE ─────────────────────────────────────
function _renderDevHealth(el) {
  el.innerHTML = `
    ${_devTabBar()}
    <div style="text-align:center;padding:40px 0;color:var(--text3);font-size:13px">
      <div style="font-size:24px;margin-bottom:8px">📊</div>
      Carregando dados de saúde...
    </div>`;
  _devLoadHealth(el);
}

async function _devLoadHealth(el) {
  const stats = await dbGetHealthStats();
  if (!stats) {
    el.innerHTML = `${_devTabBar()}<div style="text-align:center;padding:40px;color:var(--red)">Erro ao carregar dados de saúde.</div>`;
    return;
  }

  const { total_users, users_with_data, recent_errors, user_activity } = stats;
  const activeRate = total_users > 0 ? Math.round((users_with_data / total_users) * 100) : 0;

  // Cards de métricas
  const metricsHtml = `
  <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:12px;margin-bottom:20px">
    ${[
      { label: 'Usuários totais',   value: total_users,    icon: '👥', color: 'var(--accent)' },
      { label: 'Com dados reais',   value: users_with_data, icon: '📦', color: 'var(--green)' },
      { label: 'Taxa de ativação',  value: activeRate + '%', icon: '📈', color: 'var(--orange)' },
    ].map(c => `
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:14px;text-align:center">
      <div style="font-size:20px;margin-bottom:6px">${c.icon}</div>
      <div style="font-size:22px;font-weight:700;color:${c.color};font-family:var(--mono)">${c.value}</div>
      <div style="font-size:11px;color:var(--text3);margin-top:3px">${c.label}</div>
    </div>`).join('')}
  </div>`;

  // Tabela de atividade de usuários
  const actRows = (user_activity || []).map(u => {
    const lastSeen = u.last_sign_in_at
      ? new Date(u.last_sign_in_at).toLocaleDateString('pt-BR', { day:'2-digit', month:'2-digit', year:'2-digit', hour:'2-digit', minute:'2-digit' })
      : 'Nunca';
    const since = new Date(u.created_at).toLocaleDateString('pt-BR', { day:'2-digit', month:'2-digit', year:'2-digit' });
    const hasData = u.months_count > 0;
    return `
    <tr style="border-bottom:1px solid var(--border)">
      <td style="padding:8px 10px;font-size:12px;color:var(--text);max-width:180px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${u.email}</td>
      <td style="padding:8px 10px;font-size:11px;color:var(--text3);font-family:var(--mono);white-space:nowrap">${since}</td>
      <td style="padding:8px 10px;font-size:11px;color:var(--text2);font-family:var(--mono);white-space:nowrap">${lastSeen}</td>
      <td style="padding:8px 10px;text-align:center">
        <span style="font-size:10px;font-family:var(--mono);padding:2px 8px;border-radius:20px;
          background:${hasData ? 'rgba(77,255,145,.1)' : 'var(--bg3)'};
          color:${hasData ? 'var(--green)' : 'var(--text3)'};
          border:1px solid ${hasData ? 'rgba(77,255,145,.25)' : 'var(--border)'}">
          ${hasData ? u.months_count + ' meses · ' + u.entries_count + ' lançam.' : 'sem dados'}
        </span>
      </td>
    </tr>`;
  }).join('');

  const activityHtml = `
  <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin-bottom:20px">
    <div style="padding:12px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between">
      <div style="font-size:13px;font-weight:600;color:var(--text)">👤 Atividade de usuários</div>
      <div style="font-size:11px;color:var(--text3);font-family:var(--mono)">${(user_activity||[]).length} usuários</div>
    </div>
    <div style="overflow-x:auto">
      <table style="width:100%;border-collapse:collapse">
        <thead>
          <tr style="border-bottom:1px solid var(--border);background:var(--bg3)">
            <th style="padding:8px 10px;font-size:11px;color:var(--text3);font-weight:500;text-align:left">E-mail</th>
            <th style="padding:8px 10px;font-size:11px;color:var(--text3);font-weight:500;text-align:left;white-space:nowrap">Cadastro</th>
            <th style="padding:8px 10px;font-size:11px;color:var(--text3);font-weight:500;text-align:left;white-space:nowrap">Último acesso</th>
            <th style="padding:8px 10px;font-size:11px;color:var(--text3);font-weight:500;text-align:center">Dados</th>
          </tr>
        </thead>
        <tbody>${actRows || '<tr><td colspan="4" style="padding:20px;text-align:center;color:var(--text3)">Nenhum usuário</td></tr>'}</tbody>
      </table>
    </div>
  </div>`;

  // Erros recentes
  const errRows = (recent_errors || []).length
    ? (recent_errors || []).map(e => {
        const when = new Date(e.created_at).toLocaleDateString('pt-BR', { day:'2-digit', month:'2-digit', hour:'2-digit', minute:'2-digit' });
        return `
        <div style="padding:10px 14px;border-bottom:1px solid var(--border)">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:4px">
            <span style="font-size:10px;color:var(--text3);font-family:var(--mono);flex-shrink:0">${when}</span>
            <span style="font-size:11px;color:var(--text3);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${e.email || 'anon'}</span>
          </div>
          <div style="font-size:12px;color:var(--red);margin-bottom:${e.stack ? '4px' : '0'}">${e.message || '—'}</div>
          ${e.stack ? `<details><summary style="font-size:10px;color:var(--text3);cursor:pointer">Stack trace</summary><pre style="font-size:10px;color:var(--text3);white-space:pre-wrap;margin:4px 0 0;line-height:1.5">${e.stack.slice(0,600)}</pre></details>` : ''}
        </div>`;
      }).join('')
    : `<div style="padding:24px;text-align:center;color:var(--text3);font-size:12px">Nenhum erro registrado. Ótimo sinal!</div>`;

  const errorsHtml = `
  <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin-bottom:20px">
    <div style="padding:12px 16px;border-bottom:1px solid var(--border);display:flex;align-items:center;justify-content:space-between">
      <div style="font-size:13px;font-weight:600;color:var(--text)">🐛 Erros recentes</div>
      <div style="display:flex;align-items:center;gap:8px">
        <span style="font-size:11px;color:var(--text3);font-family:var(--mono)">${(recent_errors||[]).length} registros</span>
        ${(recent_errors||[]).length ? `<button onclick="_devClearErrors()" style="font-size:11px;padding:3px 10px;border-radius:6px;border:1px solid rgba(255,77,77,.3);background:rgba(255,77,77,.06);color:var(--red);cursor:pointer">Limpar</button>` : ''}
      </div>
    </div>
    ${errRows}
  </div>`;

  el.innerHTML = `${_devTabBar()}${metricsHtml}${activityHtml}${errorsHtml}
  <div style="text-align:center;margin-bottom:20px">
    <button onclick="_renderDevHealth(document.getElementById('devContent'))"
      style="font-size:12px;padding:7px 18px;border-radius:7px;border:1px solid var(--border2);background:var(--bg2);color:var(--text2);cursor:pointer">↻ Atualizar</button>
  </div>`;
}

async function _devClearErrors() {
  if (!confirm('Limpar todos os erros do banco?')) return;
  setSyncing(true);
  const { error } = await sb.from('error_logs').delete().neq('id', '00000000-0000-0000-0000-000000000000');
  setSyncing(false);
  if (error) { showToast('Erro ao limpar.', 'error'); return; }
  showToast('Erros limpos');
  _renderDevHealth(document.getElementById('devContent'));
}

// ── ABA: DEBUG ─────────────────────────────────────
function _renderDevDebug(el) {
  // Contagem de rows por tabela do usuário atual
  const counts = [
    { label: 'Meses',        val: S.months.length },
    { label: 'Lançamentos',  val: S.months.reduce((a, m) => a + m.banks.reduce((b, bk) => b + bk.entries.length, 0), 0) },
    { label: 'PIX',          val: Object.values(S.pixEntries).flat().length },
    { label: 'Contas Fixas', val: Object.values(S.recurrents).flat().length },
    { label: 'Receitas',     val: Object.values(S.incomes).flat().length },
    { label: 'Assinaturas',  val: S.subscriptions.length },
    { label: 'Parcelas',     val: S.installments.length },
    { label: 'Bancos',       val: S.globalBanks.length },
  ];

  const countsHtml = counts.map(c => `
    <div style="display:flex;justify-content:space-between;align-items:center;padding:7px 14px;border-bottom:1px solid var(--border)">
      <span style="font-size:13px;color:var(--text2)">${c.label}</span>
      <span style="font-size:13px;font-family:var(--mono);color:var(--accent);font-weight:600">${c.val}</span>
    </div>`).join('');

  // Snapshot colapsável do estado S por seção
  const sections = ['months','subscriptions','installments','globalBanks','pixEntries','recurrents','incomes','profile'];
  const snapshotHtml = sections.map(key => {
    const val = S[key];
    const json = JSON.stringify(val, null, 2);
    const preview = json.length > 200 ? json.slice(0, 200) + '...' : json;
    return `
    <details style="border-bottom:1px solid var(--border)">
      <summary style="padding:9px 14px;cursor:pointer;font-size:12px;font-family:var(--mono);color:var(--text2);list-style:none;display:flex;justify-content:space-between;align-items:center">
        <span>S.${key}</span>
        <span style="color:var(--text3);font-size:11px">${Array.isArray(val) ? val.length + ' itens' : typeof val === 'object' ? Object.keys(val||{}).length + ' chaves' : ''}</span>
      </summary>
      <pre style="margin:0;padding:10px 14px;font-size:11px;color:var(--text3);white-space:pre-wrap;word-break:break-all;background:var(--bg3);max-height:300px;overflow-y:auto;line-height:1.5">${preview}</pre>
    </details>`;
  }).join('');

  el.innerHTML = `
    ${_devTabBar()}

    <!-- Contagens -->
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin-bottom:16px">
      <div style="padding:12px 16px;border-bottom:1px solid var(--border);font-size:13px;font-weight:600;color:var(--text)">📊 Dados do usuário atual</div>
      ${countsHtml}
    </div>

    <!-- Ações -->
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:16px;margin-bottom:16px">
      <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:14px">🛠 Ações</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        <div style="display:flex;align-items:center;gap:12px">
          <div style="flex:1">
            <div style="font-size:13px;color:var(--text)">Recarregar dados</div>
            <div style="font-size:11px;color:var(--text3)">Busca tudo do Supabase sem reload da página</div>
          </div>
          <button onclick="_devReloadData()"
            style="padding:7px 16px;border-radius:7px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer;font-size:12px;white-space:nowrap">↻ Recarregar</button>
        </div>
        <div style="border-top:1px solid var(--border);padding-top:10px;display:flex;align-items:center;gap:12px">
          <div style="flex:1">
            <div style="font-size:13px;color:var(--text)">Limpar cache do Service Worker</div>
            <div style="font-size:11px;color:var(--text3)">Força atualização em todos os dispositivos</div>
          </div>
          <button onclick="_devClearSWCache()"
            style="padding:7px 16px;border-radius:7px;border:1px solid rgba(255,159,77,.3);background:rgba(255,159,77,.08);color:var(--orange);cursor:pointer;font-size:12px;white-space:nowrap">Limpar SW</button>
        </div>
        <div style="border-top:1px solid var(--border);padding-top:10px;display:flex;align-items:center;gap:12px">
          <div style="flex:1">
            <div style="font-size:13px;color:var(--text)">Ver erros recentes</div>
            <div style="font-size:11px;color:var(--text3)">Últimos erros capturados desta conta</div>
          </div>
          <button onclick="_devTab='health';renderDev()"
            style="padding:7px 16px;border-radius:7px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer;font-size:12px;white-space:nowrap">Abrir Saúde</button>
        </div>
      </div>
    </div>

    <!-- Snapshot do estado S -->
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;overflow:hidden;margin-bottom:20px">
      <div style="padding:12px 16px;border-bottom:1px solid var(--border);display:flex;justify-content:space-between;align-items:center">
        <div style="font-size:13px;font-weight:600;color:var(--text)">🗂 Estado global (S)</div>
        <button onclick="_devCopyState()" style="font-size:11px;padding:4px 10px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);cursor:pointer">Copiar JSON</button>
      </div>
      ${snapshotHtml}
    </div>`;
}

async function _devReloadData() {
  setSyncing(true);
  await loadAllFromSupabase();
  setSyncing(false);
  renderDev();
  showToast('✓ Dados recarregados');
}

async function _devClearSWCache() {
  if (!confirm('Limpar todos os caches do Service Worker?')) return;
  if ('caches' in window) {
    const keys = await caches.keys();
    await Promise.all(keys.map(k => caches.delete(k)));
    showToast('Cache limpo. Recarregando...');
    setTimeout(() => window.location.reload(true), 800);
  } else {
    showToast('Service Worker não disponível.', 'error');
  }
}

function _devCopyState() {
  const snap = {};
  ['months','subscriptions','installments','globalBanks','pixEntries','recurrents','incomes','profile'].forEach(k => { snap[k] = S[k]; });
  navigator.clipboard?.writeText(JSON.stringify(snap, null, 2))
    .then(() => showToast('✓ Estado copiado para o clipboard'))
    .catch(() => showToast('Erro ao copiar.', 'error'));
}

// ── ABA: GESTÃO DE USUÁRIOS ────────────────────────
function _renderDevUsersManagement(el) {
  el.innerHTML = `
    ${_devTabBar()}
    <div style="text-align:center;padding:40px 0;color:var(--text3);font-size:13px">
      <div style="font-size:24px;margin-bottom:8px">👤</div>
      Carregando usuários...
    </div>`;
  _devLoadUsersManagement(el);
}

async function _devLoadUsersManagement(el) {
  const users = await dbGetAllUsers();
  if (!users) {
    el.innerHTML = `${_devTabBar()}<div style="text-align:center;padding:40px;color:var(--red)">Erro ao carregar usuários.</div>`;
    return;
  }

  // Ordena por volume de dados (entries_count desc) para o ranking
  const ranked = [...users].sort((a, b) => (b.entries_count + b.months_count * 10) - (a.entries_count + a.months_count * 10));

  const rows = users.map(u => {
    const isMe = u.email === currentUser?.email;
    const lastSeen = u.last_sign_in_at
      ? new Date(u.last_sign_in_at).toLocaleDateString('pt-BR', { day:'2-digit', month:'2-digit', year:'2-digit', hour:'2-digit', minute:'2-digit' })
      : 'Nunca';
    const rank = ranked.findIndex(r => r.id === u.id) + 1;
    const hasData = u.months_count > 0;
    const medal = rank === 1 ? '🥇' : rank === 2 ? '🥈' : rank === 3 ? '🥉' : `#${rank}`;
    return `
    <div style="background:var(--bg2);border:1px solid ${u.disabled ? 'rgba(255,77,77,.3)' : 'var(--border)'};border-radius:10px;padding:14px 16px;margin-bottom:10px;${u.disabled ? 'opacity:.6' : ''}">
      <div style="display:flex;align-items:flex-start;gap:12px">
        <div style="font-size:18px;flex-shrink:0;padding-top:2px">${medal}</div>
        <div style="flex:1;min-width:0">
          <div style="display:flex;align-items:center;gap:8px;flex-wrap:wrap;margin-bottom:4px">
            <span style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${u.email}</span>
            ${u.nickname ? `<span style="font-size:11px;color:var(--accent);font-family:var(--mono)">${u.nickname}</span>` : ''}
            ${isMe ? `<span style="font-size:10px;background:rgba(77,159,255,.15);color:var(--accent);border:1px solid rgba(77,159,255,.3);border-radius:20px;padding:1px 8px;font-family:var(--mono)">você</span>` : ''}
            ${u.disabled ? `<span style="font-size:10px;background:rgba(255,77,77,.1);color:var(--red);border:1px solid rgba(255,77,77,.3);border-radius:20px;padding:1px 8px;font-family:var(--mono)">desativado</span>` : ''}
          </div>
          <div style="display:flex;gap:16px;flex-wrap:wrap">
            <span style="font-size:11px;color:var(--text3);font-family:var(--mono)">cadastro: ${new Date(u.created_at).toLocaleDateString('pt-BR')}</span>
            <span style="font-size:11px;color:var(--text3);font-family:var(--mono)">acesso: ${lastSeen}</span>
          </div>
          <div style="display:flex;gap:8px;flex-wrap:wrap;margin-top:6px">
            ${hasData ? `
              <span style="font-size:10px;padding:2px 8px;border-radius:20px;background:rgba(77,255,145,.08);color:var(--green);border:1px solid rgba(77,255,145,.2);font-family:var(--mono)">${u.months_count} meses</span>
              <span style="font-size:10px;padding:2px 8px;border-radius:20px;background:rgba(77,159,255,.08);color:var(--accent);border:1px solid rgba(77,159,255,.2);font-family:var(--mono)">${u.entries_count} lançam.</span>
              <span style="font-size:10px;padding:2px 8px;border-radius:20px;background:rgba(255,159,77,.08);color:var(--orange);border:1px solid rgba(255,159,77,.2);font-family:var(--mono)">${u.subs_count} assin.</span>
            ` : `<span style="font-size:10px;color:var(--text3);font-family:var(--mono)">sem dados ainda</span>`}
          </div>
        </div>
        ${!isMe ? `
        <button onclick="_devToggleUserDisabled('${u.id}', ${!u.disabled})"
          style="font-size:11px;padding:5px 12px;border-radius:6px;border:1px solid ${u.disabled ? 'rgba(77,255,145,.3)' : 'rgba(255,77,77,.3)'};background:${u.disabled ? 'rgba(77,255,145,.08)' : 'rgba(255,77,77,.08)'};color:${u.disabled ? 'var(--green)' : 'var(--red)'};cursor:pointer;white-space:nowrap;flex-shrink:0">
          ${u.disabled ? '✓ Reativar' : '⊘ Desativar'}
        </button>` : ''}
      </div>
    </div>`;
  }).join('');

  el.innerHTML = `
    ${_devTabBar()}
    <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:16px">
      <div>
        <div style="font-size:15px;font-weight:600;color:var(--text)">${users.length} usuários cadastrados</div>
        <div style="font-size:12px;color:var(--text3)">${users.filter(u => u.months_count > 0).length} com dados · ${users.filter(u => u.disabled).length} desativados</div>
      </div>
      <button onclick="_renderDevUsersManagement(document.getElementById('devContent'))"
        style="font-size:12px;padding:6px 14px;border-radius:7px;border:1px solid var(--border2);background:var(--bg2);color:var(--text2);cursor:pointer">↻ Atualizar</button>
    </div>
    ${rows}`;
}

async function _devToggleUserDisabled(userId, disabled) {
  const action = disabled ? 'desativar' : 'reativar';
  if (!confirm(`Confirma ${action} este usuário?`)) return;
  setSyncing(true);
  const ok = await dbSetUserDisabled(userId, disabled);
  setSyncing(false);
  if (!ok) { showToast('Erro ao atualizar usuário.', 'error'); return; }
  showToast(disabled ? 'Usuário desativado' : 'Usuário reativado');
  _renderDevUsersManagement(document.getElementById('devContent'));
}

// ── ABA: PUSH ──────────────────────────────────────
function _renderDevPush(el) {
  const vapidOk = !!(typeof VAPID_PUBLIC_KEY !== 'undefined' && VAPID_PUBLIC_KEY);
  el.innerHTML = `
    ${_devTabBar()}
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:16px;margin-bottom:16px">
      <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:10px">⚙️ Status</div>
      <div style="display:flex;flex-direction:column;gap:8px">
        <div style="display:flex;justify-content:space-between;align-items:center;font-size:13px">
          <span style="color:var(--text2)">VAPID configurado</span>
          <span style="font-family:var(--mono);font-size:12px;padding:2px 10px;border-radius:20px;
            background:${vapidOk ? 'rgba(77,255,145,.1)' : 'rgba(255,77,77,.1)'};
            color:${vapidOk ? 'var(--green)' : 'var(--red)'};
            border:1px solid ${vapidOk ? 'rgba(77,255,145,.25)' : 'rgba(255,77,77,.25)'}">
            ${vapidOk ? '✓ sim' : '✗ não'}
          </span>
        </div>
        ${!vapidOk ? `<div style="font-size:11px;color:var(--text3);line-height:1.5">
          Para ativar: gere as VAPID keys (<span style="font-family:var(--mono)">npx web-push generate-vapid-keys</span>), adicione
          <span style="font-family:var(--mono)">VAPID_PUBLIC_KEY</span>, <span style="font-family:var(--mono)">VAPID_PRIVATE_KEY</span> e
          <span style="font-family:var(--mono)">VAPID_MAILTO</span> nas secrets do Supabase, e cole a chave pública em
          <span style="font-family:var(--mono)">js/changelog.js → VAPID_PUBLIC_KEY</span>.
        </div>` : ''}
        <div style="display:flex;justify-content:space-between;align-items:center;font-size:13px">
          <span style="color:var(--text2)">Assinaturas ativas</span>
          <span id="devPushSubCount" style="font-family:var(--mono);font-size:12px;color:var(--accent)">—</span>
        </div>
      </div>
    </div>

    <!-- Enviar notificação -->
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:16px;margin-bottom:16px">
      <div style="font-size:13px;font-weight:600;color:var(--text);margin-bottom:14px">📤 Enviar para todos</div>
      <div style="margin-bottom:10px">
        <label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px">Título</label>
        <input id="devPushTitle" type="text" placeholder="ex: Nova atualização disponível"
          style="width:100%;box-sizing:border-box;padding:8px 12px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px">
      </div>
      <div style="margin-bottom:14px">
        <label style="font-size:11px;color:var(--text3);display:block;margin-bottom:4px">Mensagem</label>
        <textarea id="devPushBody" rows="3" placeholder="Texto da notificação..."
          style="width:100%;box-sizing:border-box;padding:8px 12px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px;resize:vertical;line-height:1.5"></textarea>
      </div>
      <div style="display:flex;justify-content:space-between;align-items:center">
        <div id="devPushResult" style="font-size:12px;color:var(--text3)"></div>
        <button onclick="_devSendPush()"
          style="padding:8px 18px;border-radius:7px;background:var(--accent);color:#fff;border:none;cursor:pointer;font-size:13px;font-weight:500">
          Enviar para todos
        </button>
      </div>
    </div>`;

  // Carrega contagem de assinaturas
  dbGetPushSubscriptionCount().then(n => {
    const el = document.getElementById('devPushSubCount');
    if (el) el.textContent = n + (n === 1 ? ' dispositivo' : ' dispositivos');
  });
}

async function _devSendPush() {
  const title = (document.getElementById('devPushTitle')?.value || '').trim();
  const body  = (document.getElementById('devPushBody')?.value || '').trim();
  if (!title || !body) { showToast('Preencha título e mensagem.', 'error'); return; }

  const btn = document.querySelector('#devContent button[onclick="_devSendPush()"]');
  if (btn) { btn.disabled = true; btn.textContent = 'Enviando...'; }

  setSyncing(true);
  const result = await dbSendPushToAll(title, body);
  setSyncing(false);

  if (btn) { btn.disabled = false; btn.textContent = 'Enviar para todos'; }

  const el = document.getElementById('devPushResult');
  if (result) {
    showToast(`✓ Enviado para ${result.sent} de ${result.total} dispositivos`);
    if (el) el.textContent = `✓ ${result.sent}/${result.total} enviados${result.failed ? ` · ${result.failed} falhas` : ''}`;
  } else {
    showToast('Erro ao enviar notificações.', 'error');
    if (el) el.textContent = 'Erro ao enviar.';
  }
}

// ── ABA: DEVS ──────────────────────────────────────
function _renderDevUsers(el) {
  const devs = S.devUsers;

  const rows = devs.map(d => {
    const isMe = d.email === currentUser?.email;
    const canRemove = devs.length > 1;
    const warnMe = isMe ? ' (você)' : '';
    return `
    <div style="display:flex;align-items:center;gap:12px;padding:12px 16px;background:var(--bg2);border:1px solid var(--border);border-radius:8px;margin-bottom:8px">
      <div style="width:32px;height:32px;border-radius:50%;background:var(--bg3);border:1px solid var(--border2);display:flex;align-items:center;justify-content:center;font-size:14px;flex-shrink:0">
        ${isMe ? '⭐' : '👤'}
      </div>
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;color:var(--text);font-weight:${isMe ? '600' : '400'}">${d.email}${warnMe}</div>
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono)">dev desde ${new Date(d.addedAt).toLocaleDateString('pt-BR')}</div>
      </div>
      ${canRemove
        ? `<button onclick="_devRemoveUser('${d.id}', '${d.email}', ${isMe})"
            style="font-size:11px;padding:4px 10px;border-radius:6px;border:1px solid rgba(255,77,77,.3);background:rgba(255,77,77,.08);color:var(--red);cursor:pointer;flex-shrink:0">Remover</button>`
        : `<span style="font-size:11px;color:var(--text3);padding:4px 8px">único dev</span>`}
    </div>`;
  }).join('');

  el.innerHTML = `
    ${_devTabBar()}
    <div style="margin-bottom:16px">
      <div style="font-size:15px;font-weight:600;color:var(--text);margin-bottom:2px">Desenvolvedores</div>
      <div style="font-size:12px;color:var(--text3)">${devs.length} dev(s) com acesso ao painel</div>
    </div>
    ${rows}
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;padding:16px;margin-top:16px">
      <div style="font-size:13px;font-weight:500;color:var(--text);margin-bottom:10px">Adicionar dev por e-mail</div>
      <div style="display:flex;gap:8px">
        <input id="devNewEmail" type="email" placeholder="email@exemplo.com"
          style="flex:1;padding:8px 12px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text);font-size:13px"
          onkeydown="if(event.key==='Enter')_devAddUser()">
        <button onclick="_devAddUser()"
          style="padding:8px 16px;border-radius:6px;background:var(--accent);color:#fff;border:none;cursor:pointer;font-size:13px;font-weight:500;white-space:nowrap">+ Adicionar</button>
      </div>
    </div>`;
}

async function _devAddUser() {
  const input = document.getElementById('devNewEmail');
  const email = (input?.value || '').trim().toLowerCase();
  if (!email || !email.includes('@')) { showToast('E-mail inválido.', 'error'); return; }
  if (S.devUsers.some(d => d.email === email)) { showToast('Já é dev.', 'error'); return; }

  setSyncing(true);
  const added = await dbClaimDev(email);
  setSyncing(false);

  if (!added) { showToast('Erro ao adicionar dev.', 'error'); return; }
  S.devUsers.push(added);
  renderDev();
  showToast(`✓ ${email} adicionado como dev`);
}

async function _devRemoveUser(id, email, isMe) {
  const msg = isMe
    ? `Você vai perder seu próprio acesso ao Dev Panel. Tem certeza?`
    : `Remover ${email} como dev?`;
  if (!confirm(msg)) return;

  setSyncing(true);
  await dbRemoveDev(id);
  setSyncing(false);

  S.devUsers = S.devUsers.filter(d => d.id !== id);

  if (isMe) {
    S.isDev = false;
    const devNav = document.getElementById('nav-dev');
    if (devNav) devNav.style.display = 'none';
    showView('dash');
    showToast('Acesso dev removido');
  } else {
    renderDev();
    showToast('Dev removido');
  }
}

// ── ABA: APP SETTINGS ──────────────────────────────
async function dbSetAppSetting(key, value) {
  const { error } = await sb.from('app_settings').upsert({ key, value: String(value) }, { onConflict: 'key' });
  if (error) { showToast('Erro ao salvar configuração.', 'error'); return false; }
  return true;
}

async function _devToggleAppSetting(key) {
  const current = key === 'pj_available' ? S.appSettings.pjAvailable : S.appSettings.updateNotify;
  const next = !current;
  const ok = await dbSetAppSetting(key, next);
  if (!ok) return;
  if (key === 'pj_available') S.appSettings.pjAvailable = next;
  else S.appSettings.updateNotify = next;
  renderDev();
  showToast(`✓ ${key === 'pj_available' ? 'PJ' : 'Update notify'}: ${next ? 'ativado' : 'desativado'}`);
}

function _renderDevApp(el) {
  const pjOn  = S.appSettings?.pjAvailable  || false;
  const updOn = S.appSettings?.updateNotify || false;

  const toggle = (active) => active
    ? `<span style="display:inline-flex;align-items:center;gap:6px;padding:4px 12px;border-radius:20px;background:rgba(77,255,145,.12);border:1px solid rgba(77,255,145,.25);color:var(--green);font-size:12px;font-family:var(--mono)">● Ativo</span>`
    : `<span style="display:inline-flex;align-items:center;gap:6px;padding:4px 12px;border-radius:20px;background:var(--bg3);border:1px solid var(--border2);color:var(--text3);font-size:12px;font-family:var(--mono)">○ Inativo</span>`;

  const row = (label, sub, key, active) => `
    <div style="display:flex;align-items:center;gap:12px;padding:14px 16px;border-bottom:1px solid var(--border)">
      <div style="flex:1;min-width:0">
        <div style="font-size:13px;font-weight:500;color:var(--text)">${label}</div>
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-top:2px">${sub}</div>
      </div>
      ${toggle(active)}
      <button onclick="_devToggleAppSetting('${key}')"
        style="padding:6px 14px;border-radius:6px;border:1px solid var(--border2);background:var(--bg3);color:var(--text2);font-size:12px;cursor:pointer;white-space:nowrap;flex-shrink:0">
        ${active ? 'Desativar' : 'Ativar'}
      </button>
    </div>`;

  el.innerHTML = `
    ${_devTabBar()}
    <div style="margin-bottom:16px">
      <div style="font-size:15px;font-weight:600;color:var(--text);margin-bottom:2px">Configurações do App</div>
      <div style="font-size:12px;color:var(--text3)">Controles globais que afetam todos os usuários</div>
    </div>
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:10px;overflow:hidden">
      ${row('Modo PJ', 'Libera a opção de ativar PJ no perfil de todos os usuários', 'pj_available', pjOn)}
      ${row('Notificação de atualização', 'Recarrega o app automaticamente quando o SW for atualizado', 'update_notify', updOn)}
    </div>
    <div style="margin-top:12px;font-size:11px;color:var(--text3);font-family:var(--mono);text-align:center">
      Alterações têm efeito imediato para novos logins. Usuários com sessão aberta precisam recarregar.
    </div>`;
}

/* ── js/profile.js ── */
// ══════════════════════════════════════════════════
// PROFILE.JS — Área do usuário
// ══════════════════════════════════════════════════

function _profileDisplayName() {
  return S.profile?.nickname || currentUser?.email || '';
}

function _profileInitials(str) {
  if (!str) return '?';
  const name = str.includes('@') ? str.split('@')[0] : str;
  const parts = name.trim().split(/[\s._\-+]+/).filter(Boolean);
  if (parts.length >= 2 && parts[1].length > 0)
    return (parts[0][0] + parts[1][0]).toUpperCase();
  return name.slice(0, 2).toUpperCase();
}

function _profileColor(str) {
  const palette = ['#4d9fff','#f06595','#51cf66','#ffd43b','#cc5de8','#ff6b6b','#74c0fc','#ff922b','#20c997'];
  const hash = (str || '').split('').reduce((a, c) => a + c.charCodeAt(0), 0);
  return palette[hash % palette.length];
}

function _profileAvatarHtml(size, fontSize) {
  const display = _profileDisplayName();
  const s = size || 48; const f = fontSize || 15;
  return `<div style="width:${s}px;height:${s}px;border-radius:50%;background:${_profileColor(display)};
    display:flex;align-items:center;justify-content:center;font-size:${f}px;font-weight:700;
    color:#fff;flex-shrink:0;font-family:var(--mono);letter-spacing:1px">${_profileInitials(display)}</div>`;
}

// Atualiza o avatar pequeno na sidebar
function _profileUpdateSidebarAvatar() {
  const el = document.getElementById('userAvatar');
  if (!el || !currentUser?.email) return;
  const display = _profileDisplayName();
  el.textContent = _profileInitials(display);
  el.style.background = _profileColor(display);

  // Atualiza o texto exibido na sidebar (apelido ou email)
  const emailEl = document.getElementById('userEmail');
  if (emailEl) emailEl.textContent = S.profile?.nickname || currentUser.email;
}

function renderProfile() {
  const el = document.getElementById('profileContent');
  if (!el || !currentUser) return;

  const email = currentUser.email || '';
  const nickname = S.profile?.nickname || '';
  const since = currentUser.created_at
    ? new Date(currentUser.created_at).toLocaleDateString('pt-BR', { day: '2-digit', month: 'long', year: 'numeric' })
    : '—';

  const totalMonths    = S.months.length;
  const totalEntries   = S.months.reduce((a, m) => a + m.banks.reduce((b, bk) => b + bk.entries.length, 0), 0);
  const totalSubs      = S.subscriptions.length;
  const totalInst      = S.installments.length;
  const privacyOn      = document.documentElement.getAttribute('data-privacy') === 'on';

  el.innerHTML = `
  <div style="max-width:540px;margin:0 auto;padding:20px 20px 60px">

    <!-- Avatar + Info -->
    <div style="display:flex;align-items:center;gap:16px;padding:20px;background:var(--bg2);border:1px solid var(--border);border-radius:14px;margin-bottom:16px">
      ${_profileAvatarHtml(64, 22)}
      <div style="min-width:0;flex:1">
        <div style="font-size:14px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${nickname || email}</div>
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-top:2px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${nickname ? email : ''}</div>
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-top:4px">Membro desde ${since}</div>
        <div style="display:inline-flex;align-items:center;gap:5px;margin-top:8px;background:rgba(77,255,145,.1);border:1px solid rgba(77,255,145,.2);border-radius:20px;padding:2px 10px">
          <div style="width:5px;height:5px;border-radius:50%;background:var(--green)"></div>
          <span style="font-size:10px;color:var(--green);font-family:var(--mono)">conta ativa</span>
        </div>
      </div>
    </div>

    <!-- Nome / Apelido -->
    <div class="profile-card" style="margin-bottom:12px">
      <div class="profile-card-head">👤 Nome de exibição</div>
      <div style="padding:14px 16px">
        <div style="font-size:12px;color:var(--text3);font-family:var(--mono);margin-bottom:10px">
          Como você quer ser chamado no app. Aparece na sidebar e no avatar.
        </div>
        <div style="display:flex;gap:8px;align-items:center">
          <input
            type="text"
            id="profileNicknameInput"
            style="flex:1;padding:8px 12px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;outline:none;font-family:inherit"
            placeholder="Seu nome ou apelido"
            maxlength="40"
            value="${nickname.replace(/"/g, '&quot;')}"
            onkeydown="if(event.key==='Enter')_profileSaveNickname()"
          >
          <button class="btn btn-primary btn-sm" onclick="_profileSaveNickname()" id="profileNicknameBtn">Salvar</button>
          ${nickname ? `<button class="btn btn-ghost btn-sm" onclick="_profileClearNickname()" title="Remover apelido" style="padding:6px 10px">✕</button>` : ''}
        </div>
      </div>
    </div>

    <!-- Segurança -->
    <div class="profile-card" style="margin-bottom:12px">
      <div class="profile-card-head">🔒 Segurança</div>
      <button class="profile-row" onclick="openModal('mChangePwd')">
        <div class="profile-row-info">
          <span class="profile-row-title">Trocar senha</span>
          <span class="profile-row-sub">Defina uma nova senha para sua conta</span>
        </div>
        <svg width="15" height="15" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
      <button class="profile-row" onclick="_profileSignOutAll()">
        <div class="profile-row-info">
          <span class="profile-row-title">Encerrar todas as sessões</span>
          <span class="profile-row-sub">Desconecta de todos os dispositivos</span>
        </div>
        <svg width="15" height="15" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
    </div>

    <!-- Configurações -->
    <div class="profile-card" style="margin-bottom:12px">
      <div class="profile-card-head">⚙️ Configurações</div>
      <div class="profile-row" style="cursor:default">
        <div class="profile-row-info">
          <span class="profile-row-title">Tema</span>
          <span class="profile-row-sub">Aparência do aplicativo</span>
        </div>
        <button class="profile-toggle" onclick="toggleTheme();renderProfile()">
          ${S.theme === 'dark' ? '🌙 Escuro' : '☀️ Claro'}
        </button>
      </div>
      <div class="profile-row" style="cursor:default">
        <div class="profile-row-info">
          <span class="profile-row-title">Modo privacidade</span>
          <span class="profile-row-sub">Oculta valores na tela</span>
        </div>
        <button class="profile-toggle" onclick="togglePrivacy();renderProfile()">
          ${privacyOn ? '🙈 Ativado' : '👁 Desativado'}
        </button>
      </div>
      ${S.appSettings?.pjAvailable ? `
      <div class="profile-row" style="cursor:default">
        <div class="profile-row-info">
          <span class="profile-row-title">Modo PJ</span>
          <span class="profile-row-sub">Ativa contexto separado para pessoa jurídica</span>
        </div>
        <button class="profile-toggle" onclick="_profileTogglePJ()" id="profilePJToggle">
          ${S.profile?.pjEnabled ? '🏢 Ativado' : '💼 Desativado'}
        </button>
      </div>
      ${S.profile?.pjEnabled ? _profilePJSubContextsHtml() : ''}` : `
      <div class="profile-row" style="cursor:default;opacity:.5;pointer-events:none">
        <div class="profile-row-info">
          <span class="profile-row-title">Modo PJ</span>
          <span class="profile-row-sub">Ativa contexto separado para pessoa jurídica</span>
        </div>
        <span class="profile-badge-soon">em breve</span>
      </div>`}
      <div class="profile-row" style="cursor:default" id="profilePushRow">
        <div class="profile-row-info">
          <span class="profile-row-title">Notificações push</span>
          <span class="profile-row-sub" id="profilePushSub">Alertas mesmo com o app fechado</span>
        </div>
        <button class="profile-toggle" id="profilePushToggle" onclick="_profileTogglePush()">
          ${localStorage.getItem('fin_push_enabled') === '1' ? '🔔 Ativado' : '🔕 Desativado'}
        </button>
      </div>
      <div class="profile-row" style="cursor:default;opacity:.45;pointer-events:none">
        <div class="profile-row-info">
          <span class="profile-row-title">Moeda padrão</span>
          <span class="profile-row-sub">R$, US$, €...</span>
        </div>
        <span class="profile-badge-soon">em breve</span>
      </div>
    </div>

    <!-- Meus Dados -->
    <div class="profile-card" style="margin-bottom:12px">
      <div class="profile-card-head">
        📦 Meus Dados
        <span style="font-size:11px;color:var(--text3);font-family:var(--mono);font-weight:400;margin-left:8px">
          ${totalMonths} meses · ${totalEntries} lançamentos · ${totalSubs} assinaturas · ${totalInst} parcelas
        </span>
      </div>
      <button class="profile-row" onclick="_profileExportData()">
        <div class="profile-row-info">
          <span class="profile-row-title">Exportar meus dados</span>
          <span class="profile-row-sub">Baixa JSON completo com tudo — meses, lançamentos, assinaturas</span>
        </div>
        <svg width="15" height="15" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
      </button>
      <button class="profile-row" onclick="openModal('mPrivacyPolicy')">
        <div class="profile-row-info">
          <span class="profile-row-title">Política de privacidade</span>
          <span class="profile-row-sub">Como seus dados são tratados (LGPD)</span>
        </div>
        <svg width="15" height="15" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><polyline points="9 18 15 12 9 6"/></svg>
      </button>
    </div>

    <!-- Zona de Perigo -->
    <div class="profile-card profile-card-danger" style="margin-bottom:20px">
      <div class="profile-card-head" style="color:var(--red)">⚠️ Zona de Perigo</div>
      <button class="profile-row" onclick="logout()">
        <div class="profile-row-info">
          <span class="profile-row-title">Sair da conta</span>
          <span class="profile-row-sub">Encerra a sessão neste dispositivo</span>
        </div>
        <svg width="15" height="15" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24"><path d="M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4"/><polyline points="16 17 21 12 16 7"/><line x1="21" y1="12" x2="9" y2="12"/></svg>
      </button>
      <button class="profile-row" onclick="openModal('mDeleteAccount')">
        <div class="profile-row-info">
          <span class="profile-row-title" style="color:var(--red)">Excluir minha conta</span>
          <span class="profile-row-sub">Remove todos os seus dados permanentemente</span>
        </div>
        <svg width="15" height="15" fill="none" stroke="var(--red)" stroke-width="2.5" viewBox="0 0 24 24"><polyline points="3 6 5 6 21 6"/><path d="M19 6l-1 14a2 2 0 0 1-2 2H8a2 2 0 0 1-2-2L5 6"/><path d="M10 11v6M14 11v6"/><path d="M9 6V4a1 1 0 0 1 1-1h4a1 1 0 0 1 1 1v2"/></svg>
      </button>
    </div>

    <div style="text-align:center;font-size:11px;color:var(--text3);font-family:var(--mono)">
      Finanças v${APP_VERSION} · Dados protegidos conforme a LGPD
    </div>

  </div>`;
}

function _profilePJSubContextsHtml() {
  const pjRoot = S.contexts.find(c => c.type === 'pj' && !c.parentId);
  if (!pjRoot) return '';
  const subs = S.contexts.filter(c => c.parentId === pjRoot.id);
  return `
    <div style="padding:12px 16px;border-top:1px solid var(--border)">
      <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-bottom:10px">
        Sub-contextos PJ — separe por empresa, projeto ou cliente
      </div>
      <div id="pjSubsList" style="margin-bottom:10px">
        ${subs.length === 0 ? `<div style="font-size:12px;color:var(--text3);font-style:italic">Nenhum sub-contexto criado.</div>` :
          subs.map(s => `
            <div style="display:flex;align-items:center;gap:8px;padding:6px 0;border-bottom:1px solid var(--border2)">
              <span style="flex:1;font-size:12px;color:var(--text);font-family:var(--mono)">🏢 ${s.name}</span>
              <button class="btn btn-ghost btn-sm" onclick="_profileDeleteSubCtx('${s.id}')" style="padding:4px 8px;font-size:11px">✕</button>
            </div>`).join('')}
      </div>
      <div style="display:flex;gap:8px">
        <input type="text" id="newSubCtxInput" placeholder="Ex: Freelance, Empresa X..."
          style="flex:1;padding:7px 10px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:12px;outline:none;font-family:inherit"
          maxlength="40" onkeydown="if(event.key==='Enter')_profileAddSubCtx()">
        <button class="btn btn-primary btn-sm" onclick="_profileAddSubCtx()">+ Adicionar</button>
      </div>
    </div>`;
}

async function _profileTogglePJ() {
  const btn = document.getElementById('profilePJToggle');
  if (btn) { btn.disabled = true; btn.textContent = '...'; }
  if (S.profile.pjEnabled) {
    const ok = await dbDisablePJ();
    if (ok) {
      S.profile.pjEnabled = false;
      // Se estava no contexto PJ, volta ao pessoal
      if (S.activeContext?.type !== 'personal') {
        const personal = S.contexts.find(c => c.type === 'personal');
        if (personal) await switchContext(personal.id);
      }
      showToast('Modo PJ desativado');
      renderProfile();
      renderContextSwitcher();
    } else {
      showToast('Erro ao desativar. Tente novamente.', 'error');
      if (btn) { btn.disabled = false; btn.textContent = '🏢 Ativado'; }
    }
  } else {
    const ok = await dbEnablePJ();
    if (ok) {
      S.profile.pjEnabled = true;
      // Cria contexto PJ se ainda não existe
      const pjId = await dbEnsurePJContext();
      if (pjId && !S.contexts.find(c => c.id === pjId)) {
        S.contexts = await dbLoadContexts();
      }
      showToast('Modo PJ ativado! Use o seletor na barra lateral para alternar.');
      renderProfile();
      renderContextSwitcher();
    } else {
      showToast('Erro ao ativar. Tente novamente.', 'error');
      if (btn) { btn.disabled = false; btn.textContent = '💼 Desativado'; }
    }
  }
}

async function _profileAddSubCtx() {
  const input = document.getElementById('newSubCtxInput');
  const name = (input?.value || '').trim();
  if (!name) return;
  const pjRoot = S.contexts.find(c => c.type === 'pj' && !c.parentId);
  if (!pjRoot) return;
  const newCtx = await dbSaveContext({ name, type: 'pj', parentId: pjRoot.id });
  if (newCtx) {
    S.contexts.push(newCtx);
    showToast(`Sub-contexto "${name}" criado`);
    renderProfile();
    renderContextSwitcher();
  } else {
    showToast('Erro ao criar sub-contexto.', 'error');
  }
}

async function _profileDeleteSubCtx(id) {
  if (!confirm('Remover este sub-contexto? Os dados dele ainda ficam no banco.')) return;
  await dbDeleteContext(id);
  S.contexts = S.contexts.filter(c => c.id !== id);
  if (S.activeContext?.id === id) {
    const personal = S.contexts.find(c => c.type === 'personal');
    if (personal) await switchContext(personal.id);
  }
  showToast('Sub-contexto removido');
  renderProfile();
  renderContextSwitcher();
}

async function _profileSaveNickname() {
  const input = document.getElementById('profileNicknameInput');
  const btn   = document.getElementById('profileNicknameBtn');
  if (!input) return;
  const val = input.value.trim();
  btn.textContent = '...';
  btn.disabled = true;
  const ok = await dbSaveNickname(val);
  if (ok) {
    S.profile.nickname = val;
    _profileUpdateSidebarAvatar();
    showToast(val ? `Apelido salvo: ${val}` : 'Nome de exibição removido');
    renderProfile();
  } else {
    showToast('Erro ao salvar. Tente novamente.', 'error');
    btn.textContent = 'Salvar';
    btn.disabled = false;
  }
}

async function _profileClearNickname() {
  const ok = await dbSaveNickname('');
  if (ok) {
    S.profile.nickname = '';
    _profileUpdateSidebarAvatar();
    showToast('Nome de exibição removido');
    renderProfile();
  } else {
    showToast('Erro ao remover. Tente novamente.', 'error');
  }
}

async function _profileSignOutAll() {
  if (!confirm('Encerrar sessão em todos os dispositivos?')) return;
  setSyncing(true);
  await sb.auth.signOut({ scope: 'global' });
  setSyncing(false);
  showToast('Todas as sessões encerradas');
}

function _profileExportData() {
  const data = {
    exportedAt: new Date().toISOString(),
    appVersion: APP_VERSION,
    email: currentUser?.email,
    nickname: S.profile?.nickname || null,
    months: S.months,
    pixEntries: S.pixEntries,
    recurrents: S.recurrents,
    incomes: S.incomes,
    subscriptions: S.subscriptions,
    installments: S.installments,
    globalBanks: S.globalBanks,
  };
  const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `financas-backup-${new Date().toISOString().slice(0, 10)}.json`;
  a.click();
  URL.revokeObjectURL(url);
  showToast('✓ Dados exportados');
}

async function _profileTogglePush() {
  const btn = document.getElementById('profilePushToggle');
  const sub = document.getElementById('profilePushSub');
  if (btn) { btn.disabled = true; btn.textContent = '...'; }
  const enabled = localStorage.getItem('fin_push_enabled') === '1';
  let ok;
  if (enabled) {
    ok = await _disablePushNotifications();
  } else {
    ok = await _initPushNotifications();
  }
  if (btn) {
    btn.disabled = false;
    btn.textContent = localStorage.getItem('fin_push_enabled') === '1' ? '🔔 Ativado' : '🔕 Desativado';
  }
  if (sub && ok && !enabled && !VAPID_PUBLIC_KEY) {
    sub.textContent = 'VAPID não configurado — configure nas secrets do Supabase';
  }
}

async function _profileDeleteAccount() {
  const input = document.getElementById('deleteAccountInput');
  const typed = (input?.value || '').trim().toLowerCase();
  const expected = (currentUser?.email || '').toLowerCase();

  if (typed !== expected) {
    showToast('E-mail incorreto. Digite exatamente seu e-mail.', 'error');
    return;
  }

  const btn = document.getElementById('deleteAccountBtn');
  btn.textContent = 'Excluindo...';
  btn.disabled = true;

  setSyncing(true);
  const ok = await dbDeleteAccount();
  setSyncing(false);

  if (!ok) {
    showToast('Erro ao excluir conta. Tente novamente.', 'error');
    btn.textContent = 'Excluir permanentemente';
    btn.disabled = false;
    return;
  }

  closeModal('mDeleteAccount');
  currentUser = null;
  localStorage.removeItem('fin_active_ctx');
  S = { ...defaultState() };
  const devNavEl = document.getElementById('nav-dev');
  if (devNavEl) devNavEl.style.display = 'none';
  showAuthPanel('main');
  document.getElementById('authScreen').style.display = 'flex';
  showToast('Conta excluída. Até logo.');
}

/* ── js/clients.js ── */
// ══════════════════════════════════════════════════
// CLIENTS.JS — View de Clientes PJ
// ══════════════════════════════════════════════════

function renderClientsView() {
  const el = document.getElementById('view-clients');
  if (!el) return;

  // Só exibe se estiver em contexto PJ
  if (!S.activeContext || S.activeContext.type === 'personal') {
    el.innerHTML = `<div style="padding:40px;text-align:center;color:var(--text3)">
      <div style="font-size:32px;margin-bottom:12px">🏢</div>
      <div style="font-size:14px">Esta seção é exclusiva do contexto PJ.</div>
      <div style="font-size:12px;margin-top:8px">Ative o Modo PJ nas configurações do perfil e mude para o contexto PJ.</div>
    </div>`;
    return;
  }

  const clients = S.pjClients || [];

  // Calcula faturamento por cliente a partir das receitas
  const revenueByClient = {};
  Object.values(S.incomes || {}).forEach(arr => arr.forEach(inc => {
    if (inc.clientId) {
      revenueByClient[inc.clientId] = (revenueByClient[inc.clientId] || 0) + inc.amount;
    }
  }));

  el.innerHTML = `
  <div style="max-width:680px;margin:0 auto;padding:20px 20px 60px">
    <div style="display:flex;align-items:center;gap:12px;margin-bottom:20px">
      <div style="flex:1">
        <div style="font-size:13px;color:var(--text3);font-family:var(--mono)">${clients.length} cliente${clients.length !== 1 ? 's' : ''} cadastrado${clients.length !== 1 ? 's' : ''}</div>
      </div>
      <button class="btn btn-primary btn-sm" onclick="openModal('mClient')">+ Novo cliente</button>
    </div>

    ${clients.length === 0 ? `
      <div style="text-align:center;padding:48px 20px;color:var(--text3)">
        <div style="font-size:36px;margin-bottom:12px">👥</div>
        <div style="font-size:14px;font-weight:600;color:var(--text);margin-bottom:6px">Nenhum cliente ainda</div>
        <div style="font-size:12px">Cadastre seus clientes para vincular receitas e acompanhar o faturamento por cliente.</div>
      </div>
    ` : `
      <div style="display:flex;flex-direction:column;gap:8px">
        ${clients.map(c => {
          const rev = revenueByClient[c.id] || 0;
          return `
          <div style="background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:14px 16px;display:flex;align-items:center;gap:14px">
            <div style="width:40px;height:40px;border-radius:50%;background:var(--accent);display:flex;align-items:center;justify-content:center;font-size:16px;font-weight:700;color:#fff;flex-shrink:0;font-family:var(--mono)">
              ${c.name.slice(0,1).toUpperCase()}
            </div>
            <div style="flex:1;min-width:0">
              <div style="font-size:13px;font-weight:600;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${c.name}</div>
              <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-top:2px">
                ${[c.cnpj, c.email, c.phone].filter(Boolean).join(' · ') || 'Sem informações de contato'}
              </div>
            </div>
            <div style="text-align:right;flex-shrink:0">
              <div style="font-size:12px;font-weight:600;color:var(--green);font-family:var(--mono)">${rev > 0 ? fmt(rev) : '—'}</div>
              <div style="font-size:10px;color:var(--text3)">faturamento</div>
            </div>
            <div style="display:flex;gap:4px;flex-shrink:0">
              <button class="btn btn-ghost btn-sm" onclick="_clientEdit('${c.id}')" style="padding:5px 8px" title="Editar">✎</button>
              <button class="btn btn-ghost btn-sm" onclick="_clientDelete('${c.id}')" style="padding:5px 8px;color:var(--red)" title="Excluir">✕</button>
            </div>
          </div>`;
        }).join('')}
      </div>
    `}
  </div>`;
}

function _clientEdit(id) {
  const c = (S.pjClients || []).find(x => x.id === id);
  if (!c) return;
  document.getElementById('clientId').value     = c.id;
  document.getElementById('clientName').value   = c.name;
  document.getElementById('clientEmail').value  = c.email;
  document.getElementById('clientPhone').value  = c.phone;
  document.getElementById('clientCNPJ').value   = c.cnpj;
  document.getElementById('clientNotes').value  = c.notes;
  document.getElementById('mClientTitle').textContent = 'Editar cliente';
  openModal('mClient');
}

async function _clientSave() {
  const id    = document.getElementById('clientId').value;
  const name  = document.getElementById('clientName').value.trim();
  if (!name) { showToast('Informe o nome do cliente.', 'error'); return; }

  const btn = document.getElementById('clientSaveBtn');
  btn.textContent = '...'; btn.disabled = true;

  const client = {
    id: id || null,
    name,
    email: document.getElementById('clientEmail').value.trim(),
    phone: document.getElementById('clientPhone').value.trim(),
    cnpj:  document.getElementById('clientCNPJ').value.trim(),
    notes: document.getElementById('clientNotes').value.trim(),
  };

  const saved = await dbSaveClient(client);
  btn.textContent = 'Salvar'; btn.disabled = false;

  if (!saved) { showToast('Erro ao salvar cliente.', 'error'); return; }

  if (!S.pjClients) S.pjClients = [];
  const idx = S.pjClients.findIndex(x => x.id === saved.id);
  if (idx >= 0) S.pjClients[idx] = saved;
  else S.pjClients.push(saved);

  closeModal('mClient');
  showToast(id ? 'Cliente atualizado' : `Cliente "${saved.name}" adicionado`);
  renderClientsView();
}

async function _clientDelete(id) {
  const c = (S.pjClients || []).find(x => x.id === id);
  if (!confirm(`Excluir cliente "${c?.name}"? As receitas vinculadas não serão apagadas.`)) return;
  await dbDeleteClient(id);
  S.pjClients = (S.pjClients || []).filter(x => x.id !== id);
  showToast('Cliente removido');
  renderClientsView();
}

function _clientModalOpen() {
  document.getElementById('clientId').value     = '';
  document.getElementById('clientName').value   = '';
  document.getElementById('clientEmail').value  = '';
  document.getElementById('clientPhone').value  = '';
  document.getElementById('clientCNPJ').value   = '';
  document.getElementById('clientNotes').value  = '';
  document.getElementById('mClientTitle').textContent = 'Novo cliente';
}

/* ── js/taxes.js ── */
// ══════════════════════════════════════════════════
// TAXES.JS — Impostos PJ
// ══════════════════════════════════════════════════

const TAX_TYPES = ['DAS', 'IRPF', 'INSS', 'ISS', 'Outro'];

function renderTaxesView() {
  const el = document.getElementById('view-taxes');
  if (!el) return;

  if (!S.activeContext || S.activeContext.type === 'personal') {
    el.innerHTML = `<div style="padding:40px;text-align:center;color:var(--text3)">
      <div style="font-size:32px;margin-bottom:12px">🧾</div>
      <div style="font-size:14px">Esta seção é exclusiva do contexto PJ.</div>
    </div>`;
    return;
  }

  const taxes = S.pjTaxes || [];
  const pending = taxes.filter(t => !t.paid);
  const paid    = taxes.filter(t => t.paid);
  const totalPending = pending.reduce((a, t) => a + t.amount, 0);
  const totalPaid    = paid.reduce((a, t) => a + t.amount, 0);
  const taxRate      = S.activeContext.taxRate || null;

  // Faturamento bruto do contexto atual (soma de incomes)
  const grossRevenue = Object.values(S.incomes || {}).flat().reduce((a, i) => a + i.amount, 0);
  const estimatedTax = taxRate ? grossRevenue * (taxRate / 100) : null;

  el.innerHTML = `
  <div style="max-width:680px;margin:0 auto;padding:20px 20px 60px">

    <!-- Resumo -->
    <div style="display:grid;grid-template-columns:repeat(3,1fr);gap:10px;margin-bottom:20px">
      <div style="background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:14px;text-align:center">
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-bottom:4px">a pagar</div>
        <div style="font-size:16px;font-weight:700;color:var(--red);font-family:var(--mono)">${fmt(totalPending)}</div>
      </div>
      <div style="background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:14px;text-align:center">
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-bottom:4px">pago no período</div>
        <div style="font-size:16px;font-weight:700;color:var(--green);font-family:var(--mono)">${fmt(totalPaid)}</div>
      </div>
      <div style="background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:14px;text-align:center">
        <div style="font-size:11px;color:var(--text3);font-family:var(--mono);margin-bottom:4px">estimativa</div>
        <div style="font-size:16px;font-weight:700;color:var(--accent);font-family:var(--mono)">${estimatedTax !== null ? fmt(estimatedTax) : '—'}</div>
      </div>
    </div>

    <!-- Alíquota -->
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:14px 16px;margin-bottom:16px;display:flex;align-items:center;gap:12px">
      <div style="flex:1">
        <div style="font-size:12px;font-weight:600;color:var(--text)">Alíquota estimada</div>
        <div style="font-size:11px;color:var(--text3)">Usada para estimar imposto sobre o faturamento bruto</div>
      </div>
      <div style="display:flex;align-items:center;gap:6px">
        <input type="number" id="taxRateInput" min="0" max="100" step="0.1"
          value="${taxRate || ''}" placeholder="0.0"
          style="width:70px;padding:6px 8px;background:var(--bg3);border:1px solid var(--border);border-radius:8px;color:var(--text);font-size:13px;text-align:right;font-family:var(--mono);outline:none">
        <span style="font-size:13px;color:var(--text3)">%</span>
        <button class="btn btn-ghost btn-sm" onclick="_taxSaveRate()" style="padding:5px 10px">Salvar</button>
      </div>
    </div>

    <!-- Ações -->
    <div style="display:flex;justify-content:flex-end;margin-bottom:16px">
      <button class="btn btn-primary btn-sm" onclick="openModal('mTax')">+ Lançar imposto</button>
    </div>

    <!-- Lista pendentes -->
    ${pending.length > 0 ? `
    <div style="font-size:11px;font-weight:600;color:var(--text3);font-family:var(--mono);text-transform:uppercase;letter-spacing:.5px;margin-bottom:8px">Pendentes</div>
    <div style="display:flex;flex-direction:column;gap:6px;margin-bottom:16px">
      ${pending.map(t => _taxRowHtml(t)).join('')}
    </div>` : ''}

    <!-- Lista pagos -->
    ${paid.length > 0 ? `
    <div style="font-size:11px;font-weight:600;color:var(--text3);font-family:var(--mono);text-transform:uppercase;letter-spacing:.5px;margin-bottom:8px">Pagos</div>
    <div style="display:flex;flex-direction:column;gap:6px">
      ${paid.map(t => _taxRowHtml(t)).join('')}
    </div>` : ''}

    ${taxes.length === 0 ? `
    <div style="text-align:center;padding:48px 20px;color:var(--text3)">
      <div style="font-size:36px;margin-bottom:12px">🧾</div>
      <div style="font-size:14px;font-weight:600;color:var(--text);margin-bottom:6px">Nenhum imposto lançado</div>
      <div style="font-size:12px">Registre DAS, IRPF, INSS e outros impostos para acompanhar o que está pendente.</div>
    </div>` : ''}
  </div>`;
}

function _taxRowHtml(t) {
  const overdue = !t.paid && t.dueDate && t.dueDate < today();
  return `
  <div style="background:var(--bg2);border:1px solid ${overdue ? 'rgba(255,100,100,.35)' : 'var(--border)'};border-radius:10px;padding:12px 14px;display:flex;align-items:center;gap:12px">
    <div style="flex:1;min-width:0">
      <div style="display:flex;align-items:center;gap:8px">
        <span style="font-size:12px;font-weight:700;color:var(--text);font-family:var(--mono)">${t.type}</span>
        ${t.refMonth ? `<span style="font-size:10px;color:var(--text3);font-family:var(--mono)">${t.refMonth}</span>` : ''}
        ${overdue ? `<span style="font-size:10px;color:var(--red);font-family:var(--mono)">vencido</span>` : ''}
      </div>
      <div style="font-size:11px;color:var(--text3);margin-top:2px">
        ${t.dueDate ? `Vence ${new Date(t.dueDate + 'T12:00:00').toLocaleDateString('pt-BR')}` : 'Sem data'}
        ${t.notes ? ` · ${t.notes}` : ''}
      </div>
    </div>
    <div style="font-size:13px;font-weight:700;font-family:var(--mono);color:${t.paid ? 'var(--green)' : 'var(--red)'}">${fmt(t.amount)}</div>
    <button onclick="_taxTogglePaid('${t.id}',${!t.paid})"
      style="padding:4px 10px;border-radius:6px;border:1px solid var(--border);background:${t.paid ? 'rgba(81,207,102,.15)' : 'var(--bg3)'};color:${t.paid ? 'var(--green)' : 'var(--text3)'};font-size:11px;cursor:pointer;font-family:var(--mono)">
      ${t.paid ? '✓ pago' : 'marcar pago'}
    </button>
    <button onclick="_taxEdit('${t.id}')" style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:14px;padding:0 4px" title="Editar">✎</button>
    <button onclick="_taxDelete('${t.id}')" style="background:none;border:none;color:var(--text3);cursor:pointer;font-size:14px;padding:0 4px" title="Excluir">✕</button>
  </div>`;
}

async function _taxTogglePaid(id, paid) {
  const ok = await dbMarkTaxPaid(id, paid);
  if (!ok) { showToast('Erro ao atualizar.', 'error'); return; }
  const t = (S.pjTaxes || []).find(x => x.id === id);
  if (t) { t.paid = paid; t.paidAt = paid ? new Date().toISOString() : null; }
  showToast(paid ? 'Imposto marcado como pago' : 'Imposto marcado como pendente');
  renderTaxesView();
}

function _taxEdit(id) {
  const t = (S.pjTaxes || []).find(x => x.id === id);
  if (!t) return;
  document.getElementById('taxId').value      = t.id;
  document.getElementById('taxType').value    = t.type;
  document.getElementById('taxAmount').value  = t.amount;
  document.getElementById('taxDueDate').value = t.dueDate || '';
  document.getElementById('taxRefMonth').value = t.refMonth || '';
  document.getElementById('taxNotes').value   = t.notes;
  document.getElementById('mTaxTitle').textContent = 'Editar imposto';
  openModal('mTax');
}

async function _taxSave() {
  const id     = document.getElementById('taxId').value;
  const type   = document.getElementById('taxType').value;
  const amount = parseFloat(document.getElementById('taxAmount').value);
  if (!type || isNaN(amount) || amount <= 0) {
    showToast('Preencha tipo e valor.', 'error'); return;
  }
  const btn = document.getElementById('taxSaveBtn');
  btn.textContent = '...'; btn.disabled = true;

  const tax = {
    id: id || null, type, amount,
    dueDate:  document.getElementById('taxDueDate').value || null,
    refMonth: document.getElementById('taxRefMonth').value || null,
    notes:    document.getElementById('taxNotes').value.trim(),
    paid: false
  };

  const saved = await dbSaveTax(tax);
  btn.textContent = 'Salvar'; btn.disabled = false;
  if (!saved) { showToast('Erro ao salvar.', 'error'); return; }

  if (!S.pjTaxes) S.pjTaxes = [];
  const idx = S.pjTaxes.findIndex(x => x.id === saved.id);
  if (idx >= 0) S.pjTaxes[idx] = saved;
  else S.pjTaxes.push(saved);

  closeModal('mTax');
  showToast(id ? 'Imposto atualizado' : 'Imposto lançado');
  renderTaxesView();
}

async function _taxDelete(id) {
  if (!confirm('Excluir este lançamento de imposto?')) return;
  await dbDeleteTax(id);
  S.pjTaxes = (S.pjTaxes || []).filter(x => x.id !== id);
  showToast('Imposto removido');
  renderTaxesView();
}

async function _taxSaveRate() {
  const val = parseFloat(document.getElementById('taxRateInput')?.value);
  if (isNaN(val) || val < 0 || val > 100) { showToast('Alíquota inválida (0–100).', 'error'); return; }
  const ok = await dbSaveTaxRate(S.activeContext.id, val);
  if (ok) {
    S.activeContext.taxRate = val;
    showToast(`Alíquota salva: ${val}%`);
    renderTaxesView();
  } else {
    showToast('Erro ao salvar alíquota.', 'error');
  }
}

function _taxModalOpen() {
  document.getElementById('taxId').value       = '';
  document.getElementById('taxType').value     = 'DAS';
  document.getElementById('taxAmount').value   = '';
  document.getElementById('taxDueDate').value  = '';
  document.getElementById('taxRefMonth').value = '';
  document.getElementById('taxNotes').value    = '';
  document.getElementById('mTaxTitle').textContent = 'Lançar imposto';
}

/* ── js/pj-reports.js ── */
// ══════════════════════════════════════════════════
// PJ-REPORTS.JS — Relatórios PJ
// ══════════════════════════════════════════════════

function renderPJReports() {
  const el = document.getElementById('view-pjreports');
  if (!el) return;

  if (!S.activeContext || S.activeContext.type === 'personal') {
    el.innerHTML = `<div style="padding:40px;text-align:center;color:var(--text3)">
      <div style="font-size:32px;margin-bottom:12px">📊</div>
      <div style="font-size:14px">Esta seção é exclusiva do contexto PJ.</div>
    </div>`;
    return;
  }

  // Agrupa receitas por mês
  const monthRevenue = {};
  Object.entries(S.incomes || {}).forEach(([mk, arr]) => {
    monthRevenue[mk] = (monthRevenue[mk] || 0) + arr.reduce((a, i) => a + i.amount, 0);
  });

  // Agrupa gastos por mês (entries do tipo 'mine')
  const monthExpense = {};
  S.months.forEach(m => {
    m.banks.forEach(b => {
      b.entries.forEach(e => {
        if (e.owner === 'mine') {
          monthExpense[m.key] = (monthExpense[m.key] || 0) + e.amount;
        }
      });
    });
  });

  // Agrupa impostos por mês de referência
  const monthTaxes = {};
  (S.pjTaxes || []).forEach(t => {
    if (t.refMonth) {
      monthTaxes[t.refMonth] = (monthTaxes[t.refMonth] || 0) + t.amount;
    }
  });

  // Todos os meses em ordem
  const allMonths = [...new Set([
    ...Object.keys(monthRevenue),
    ...Object.keys(monthExpense),
    ...Object.keys(monthTaxes)
  ])].sort().reverse();

  const totalRevenue = Object.values(monthRevenue).reduce((a, v) => a + v, 0);
  const totalExpense = Object.values(monthExpense).reduce((a, v) => a + v, 0);
  const totalTaxes   = Object.values(monthTaxes).reduce((a, v) => a + v, 0);
  const totalNet     = totalRevenue - totalExpense - totalTaxes;

  // Faturamento por cliente
  const clientRevenue = {};
  const clients = S.pjClients || [];
  Object.values(S.incomes || {}).flat().forEach(inc => {
    if (inc.clientId) {
      clientRevenue[inc.clientId] = (clientRevenue[inc.clientId] || 0) + inc.amount;
    }
  });
  const topClients = Object.entries(clientRevenue)
    .map(([id, rev]) => ({ client: clients.find(c => c.id === id), rev }))
    .filter(x => x.client)
    .sort((a, b) => b.rev - a.rev)
    .slice(0, 5);

  el.innerHTML = `
  <div style="max-width:760px;margin:0 auto;padding:20px 20px 60px">

    <!-- Cards de totais -->
    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:10px;margin-bottom:24px">
      ${[
        { label: 'Faturamento bruto', val: totalRevenue, color: 'var(--green)' },
        { label: 'Custos totais',     val: totalExpense, color: 'var(--red)' },
        { label: 'Impostos',          val: totalTaxes,   color: 'var(--yellow)' },
        { label: 'Líquido',           val: totalNet,     color: totalNet >= 0 ? 'var(--green)' : 'var(--red)' },
      ].map(c => `
        <div style="background:var(--bg2);border:1px solid var(--border);border-radius:12px;padding:14px;text-align:center">
          <div style="font-size:10px;color:var(--text3);font-family:var(--mono);margin-bottom:4px">${c.label}</div>
          <div style="font-size:15px;font-weight:700;color:${c.color};font-family:var(--mono)">${fmt(c.val)}</div>
        </div>`).join('')}
    </div>

    <!-- Gráfico mensal (barras simples com CSS) -->
    ${allMonths.length > 0 ? `
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:14px;padding:18px;margin-bottom:20px">
      <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:16px">Faturamento por mês</div>
      <div style="display:flex;flex-direction:column;gap:10px">
        ${(() => {
          const maxVal = Math.max(...allMonths.map(mk => monthRevenue[mk] || 0), 1);
          return allMonths.slice(0, 12).map(mk => {
            const rev  = monthRevenue[mk] || 0;
            const exp  = monthExpense[mk] || 0;
            const tax  = monthTaxes[mk] || 0;
            const net  = rev - exp - tax;
            const pct  = Math.round((rev / maxVal) * 100);
            const m    = S.months.find(x => x.key === mk);
            const lbl  = m ? m.label : mk;
            return `
            <div>
              <div style="display:flex;justify-content:space-between;margin-bottom:4px">
                <span style="font-size:11px;color:var(--text3);font-family:var(--mono)">${lbl}</span>
                <span style="font-size:11px;color:var(--green);font-family:var(--mono)">${fmt(rev)}</span>
              </div>
              <div style="height:6px;background:var(--bg3);border-radius:3px;overflow:hidden">
                <div style="height:100%;width:${pct}%;background:var(--green);border-radius:3px;transition:width .3s"></div>
              </div>
              <div style="display:flex;gap:12px;margin-top:3px">
                <span style="font-size:10px;color:var(--text3)">custos ${fmt(exp)}</span>
                <span style="font-size:10px;color:var(--yellow)">impostos ${fmt(tax)}</span>
                <span style="font-size:10px;font-weight:600;color:${net >= 0 ? 'var(--green)' : 'var(--red)'}">líquido ${fmt(net)}</span>
              </div>
            </div>`;
          }).join('');
        })()}
      </div>
    </div>` : ''}

    <!-- Top clientes -->
    ${topClients.length > 0 ? `
    <div style="background:var(--bg2);border:1px solid var(--border);border-radius:14px;padding:18px;margin-bottom:20px">
      <div style="font-size:12px;font-weight:600;color:var(--text);margin-bottom:14px">Top clientes</div>
      <div style="display:flex;flex-direction:column;gap:8px">
        ${topClients.map((x, i) => {
          const pct = totalRevenue > 0 ? Math.round((x.rev / totalRevenue) * 100) : 0;
          return `
          <div style="display:flex;align-items:center;gap:10px">
            <span style="font-size:11px;color:var(--text3);font-family:var(--mono);width:16px">${i + 1}.</span>
            <span style="flex:1;font-size:12px;color:var(--text);overflow:hidden;text-overflow:ellipsis;white-space:nowrap">${x.client.name}</span>
            <span style="font-size:11px;color:var(--text3);font-family:var(--mono)">${pct}%</span>
            <span style="font-size:12px;font-weight:700;color:var(--green);font-family:var(--mono)">${fmt(x.rev)}</span>
          </div>`;
        }).join('')}
      </div>
    </div>` : ''}

    <!-- Exportar CSV -->
    <div style="text-align:center">
      <button class="btn btn-ghost btn-sm" onclick="_pjReportsExportCSV()" style="font-size:12px">
        <svg width="13" height="13" fill="none" stroke="currentColor" stroke-width="2.5" viewBox="0 0 24 24" style="margin-right:5px"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" y1="15" x2="12" y2="3"/></svg>
        Exportar para contador (CSV)
      </button>
    </div>
  </div>`;
}

function _pjReportsExportCSV() {
  const rows = [['Mês', 'Faturamento Bruto', 'Custos', 'Impostos', 'Líquido']];

  const monthRevenue = {};
  Object.entries(S.incomes || {}).forEach(([mk, arr]) => {
    monthRevenue[mk] = arr.reduce((a, i) => a + i.amount, 0);
  });
  const monthExpense = {};
  S.months.forEach(m => {
    m.banks.forEach(b => {
      b.entries.forEach(e => {
        if (e.owner === 'mine') monthExpense[m.key] = (monthExpense[m.key] || 0) + e.amount;
      });
    });
  });
  const monthTaxes = {};
  (S.pjTaxes || []).forEach(t => {
    if (t.refMonth) monthTaxes[t.refMonth] = (monthTaxes[t.refMonth] || 0) + t.amount;
  });

  const allMonths = [...new Set([
    ...Object.keys(monthRevenue), ...Object.keys(monthExpense), ...Object.keys(monthTaxes)
  ])].sort();

  allMonths.forEach(mk => {
    const rev = monthRevenue[mk] || 0;
    const exp = monthExpense[mk] || 0;
    const tax = monthTaxes[mk] || 0;
    const m   = S.months.find(x => x.key === mk);
    rows.push([m ? m.label : mk, rev.toFixed(2), exp.toFixed(2), tax.toFixed(2), (rev - exp - tax).toFixed(2)]);
  });

  const csv = rows.map(r => r.join(';')).join('\n');
  const blob = new Blob(['\uFEFF' + csv], { type: 'text/csv;charset=utf-8;' });
  const url = URL.createObjectURL(blob);
  const a = document.createElement('a');
  a.href = url;
  a.download = `relatorio-pj-${S.activeContext?.name || 'pj'}-${new Date().toISOString().slice(0, 10)}.csv`;
  a.click();
  URL.revokeObjectURL(url);
  showToast('✓ CSV exportado');
}

